const a = [
  {"id":6739,"text":"What is the most common cause of nephrotic syndrome in children?","explanation":null,"reference":null,"responses":[{"text":"Membranous nephropathy","correct":false,"visible":false},{"text":"Minimal change disease","correct":true,"visible":false},{"text":"IgA nephropathy","correct":false,"visible":false},{"text":"Membranoproliferative glomerulonephritis","correct":false,"visible":false},{"text":"Focal segmental glomerulosclerosis","correct":false,"visible":false}]},{"id":6753,"text":"What is the most common cause of drug-induced interstitial nephritis?","explanation":null,"reference":null,"responses":[{"text":"Allopurinol","correct":false,"visible":false},{"text":"Moxifloxacin","correct":false,"visible":false},{"text":"Vancomycin","correct":false,"visible":false},{"text":"Aspirin","correct":true,"visible":false},{"text":"Methotrexate","correct":false,"visible":false}]},{"id":6801,"text":"A 30-year-old male takes morphine as he feels good and also reports that it makes him feel light and relaxed. What are the two properties of this drug and its derivatives for which they are potentially used as drugs of abuse?","explanation":null,"reference":null,"responses":[{"text":"Sedative","correct":false,"visible":false},{"text":"Narcosis","correct":false,"visible":false},{"text":"Analgesia + sedation","correct":false,"visible":false},{"text":"Analgesia","correct":false,"visible":false},{"text":"Analgesia + narcosis","correct":true,"visible":false}]},{"id":6806,"text":"30-year-old Arshad came into the rehabilitation clinic as he uses cocaine and wants to quit. On assessment, he only needs the drug to satisfy his emotional and psychological needs but not getting the drug does not experience any withdrawal symptoms. What is he likely to have?","explanation":null,"reference":"Psychological dependence - an overview | sciencedirect topics. Accessed November 3, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/psychological-dependence","responses":[{"text":"Habituation","correct":false,"visible":false},{"text":"Drug addiction","correct":false,"visible":false},{"text":"Drug dependence","correct":false,"visible":false},{"text":"Psychological dependence","correct":true,"visible":false},{"text":"Physical dependence","correct":false,"visible":false}]},{"id":6813,"text":"30-year-old Ayesha came into the psychiatry department with complaints of sweating, headache, nausea, and cramping pain if she does not take heroin. What are the symptoms she is experiencing termed as?","explanation":null,"reference":"Gupta M, Gokarakonda SB, Attia FN. Withdrawal syndromes. In: StatPearls. StatPearls Publishing; 2022. Accessed October 25, 2022. http://www.ncbi.nlm.nih.gov/books/NBK459239/","responses":[{"text":"Drug habit","correct":false,"visible":false},{"text":"Drug dependence","correct":false,"visible":false},{"text":"Habituation","correct":false,"visible":false},{"text":"Tolerance","correct":false,"visible":false},{"text":"Withdrawal symptoms","correct":true,"visible":false}]},{"id":6819,"text":"A 55-year-old male came with complaints of abdominal pain, high-grade fever with altered mental state, dysuria, and hematuria. His urine DR report shows numerous pus cells, nitrite positive, and few red blood cells. The physician diagnoses him with a case of urinary tract infection. Which of the following methods of urine collection has the lowest risk of contamination?","explanation":null,"reference":null,"responses":[{"text":"Collection from catheterization","correct":false,"visible":false},{"text":"Mid-stream clean catch specimen","correct":false,"visible":false},{"text":"First morning specimen","correct":false,"visible":false},{"text":"Suprapubic aspiration","correct":true,"visible":false},{"text":"Pediatric specimen","correct":false,"visible":false}]},{"id":6820,"text":"A 40-year-old man comes with the presenting complaint of localized pain in the perineum and suprapubic area, and pain during and after ejaculation. Detailed urine and culture reports show raised white blood cell (WBC) count and growth of E. coli. What would be the diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Granulomatous prostatitis","correct":false,"visible":false},{"text":"Acute bacterial prostatitis","correct":false,"visible":false},{"text":"Chronic bacterial prostatitis","correct":true,"visible":false},{"text":"Prostatic tuberculosis","correct":false,"visible":false},{"text":"Chronic pelvic pain syndrome","correct":false,"visible":false}]},{"id":6821,"text":"A 10-year-old boy presents with a fever. On examination, he is hypertensive having a blood pressure (BP) of 140/90 mmHg. Urine analysis reveals 1+proteinuria, 3+hematuria, no ketones, no glucose, and RBC casts. On renal biopsy, hyper-cellular glomeruli containing neutrophils are noticed. The granular pattern on immune-fluorescence and electron-dense sub-epithelial “humps” on electron microscopy are also present. This child is suffering from which of the following renal diseases?","explanation":null,"reference":null,"responses":[{"text":"Membranous glomerulonephritis","correct":false,"visible":false},{"text":"Focal segmental glomerulonephritis","correct":false,"visible":false},{"text":"Post-streptococcal glomerulonephritis","correct":true,"visible":false},{"text":"Diabetic nephropathy","correct":false,"visible":false},{"text":"Minimal change disease","correct":false,"visible":false}]},{"id":6822,"text":"A 14-year-old boy presents with a history of lethargy and puffiness around his eyes. Laboratory results show serum creatinine and urea nitrogen within normal ranges. Urinalysis shows 4+proteinuria, no blood, glucose, or ketones, and a 24-hour urine protein content of 3.6 g. The child’s condition improves after a course of corticosteroid therapy. Which of the following best describes the underlying renal pathology in this child?","explanation":null,"reference":null,"responses":[{"text":"Effacement of podocyte foot processes","correct":true,"visible":false},{"text":"Reduplication of glomerular basement membrane","correct":false,"visible":false},{"text":"Increased mesangial matrix","correct":false,"visible":false},{"text":"Glomerular basement deposition of IgG antibodies","correct":false,"visible":false},{"text":"Sub-epithelial electron dense deposits","correct":false,"visible":false}]},{"id":6849,"text":"A 15-year-old teenage boy came to the psychiatry department as he wants to stop taking heroin. On assessment, he reported that he needs to frequently increase the dose of the drug to have the same effect as before. What is the teenager said to have developed?","explanation":null,"reference":"Algera MH, Olofsen E, Moss L, et al. Tolerance to opioid-induced respiratory depression in chronic high-dose opioid users: a model-based comparison with opioid-naïve individuals. Clin Pharmacol Ther. 2021;109(3):637-645. doi:10.1002/cpt.2027","responses":[{"text":"Craving of heroin","correct":false,"visible":false},{"text":"Habituation to heroin","correct":false,"visible":false},{"text":"Addiction to heroin","correct":false,"visible":false},{"text":"Tolerance to heroin","correct":true,"visible":false},{"text":"Experiencing withdrawal symptoms","correct":false,"visible":false}]},{"id":6850,"text":"A 16-year-old girl is suspected to be raped by her school teacher. She is brought in for an examination of the genitalia for signs of rape. On examination, the presence of carunculae hymenales was noted with no other obvious signs of other injuries. What do these findings suggest?","explanation":null,"reference":null,"responses":[{"text":"Suggestive of annular hymen","correct":false,"visible":false},{"text":"Suggestive of virginity","correct":false,"visible":false},{"text":"Suggestive of rape","correct":false,"visible":false},{"text":"Suggestive of congenital anomaly","correct":false,"visible":false},{"text":"Suggestive of sexual intercourse","correct":true,"visible":false}]},{"id":6851,"text":"A 2-year-old boy presented in emergency for high-grade fever. His blood complete picture showed a high white blood cells (WBCs) count and C-reactive protein (CRP). Blood culture and urine culture confirmed the presence of Pseudomonas aeruginosa. Which one of the following is true related to Pseudomonas aeruginosa?","explanation":null,"reference":null,"responses":[{"text":"Gram positive rods, indole positive","correct":false,"visible":false},{"text":"Gram positive rods, indole negative","correct":false,"visible":false},{"text":"Gram negative rods, urea negative","correct":false,"visible":false},{"text":"Gram negative rods, oxidase positive","correct":true,"visible":false},{"text":"Gram negative rods, oxidase negative","correct":false,"visible":false}]},{"id":6854,"text":"A 30-year-old man is brought into the emergency as he has overdosed on an unknown drug. On examination, his pupils are pinpoint, nonreactive to light, his breathing is sighing and pre-regular in pattern, and his body is profusely sweating. What do you think based on these findings he has overdosed on?","explanation":null,"reference":"“Drug Effects on Eyes: Redness, Dilated \u0026 Pinpoint Pupils.” American Addiction Centers, https://americanaddictioncenters.org/health-complications-addiction/signs-drug-use-eyes. Accessed 21 Nov. 2023","responses":[{"text":"Naphthalene","correct":false,"visible":false},{"text":"Kerosene oil","correct":false,"visible":false},{"text":"Milk of magnesia","correct":false,"visible":false},{"text":"Morphine","correct":true,"visible":false},{"text":"Naloxone","correct":false,"visible":false}]},{"id":6878,"text":"A 25-year-old woman was taking thiazide diuretics. After one week, she developed a rash and low-grade fever. Her blood complete picture shows increased eosinophil count. What would be the diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Drug induced Interstitial nephritis","correct":true,"visible":false},{"text":"Chronic reflux- associated pyelonephritis","correct":false,"visible":false},{"text":"Chronic obstructive pyelonephritis","correct":false,"visible":false},{"text":"Benign prostate hypertrophy","correct":false,"visible":false},{"text":"Chronic granulomatous prostatitis","correct":false,"visible":false}]},{"id":6882,"text":"A 30-year-old man started working in a shop that sold petroleum and its derived refined oil. After 2 – 3 days, he developed headache, vertigo, nausea, and vomiting. He was suspected to have developed acute poisoning. What is the most probable diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Ether poisoning","correct":false,"visible":false},{"text":"Benzene poisoning","correct":false,"visible":false},{"text":"Petroleum poisoning","correct":false,"visible":false},{"text":"Naphtha poisoning","correct":false,"visible":false},{"text":"Kerosene poisoning","correct":true,"visible":false}]},{"id":6883,"text":"A 35-year-old woman presents to the medical outpatient department (OPD) for a regular checkup. On examination, her blood pressure is slightly elevated at 180/100 mmHg. She is physically fit and follows a healthy diet. The physician decided to start antihypertensive therapy and prescribe hydrochlorothiazide. What is the possible mechanism of action of hydrochlorothiazide?","explanation":null,"reference":"Herman LL, Bashir K. Hydrochlorothiazide. In: StatPearls. StatPearls Publishing; 2022. Accessed November 3, 2022. http://www.ncbi.nlm.nih.gov/books/NBK430766/","responses":[{"text":"Inhibits reabsorption of sodium chloride in the distal convoluted tubule","correct":true,"visible":false},{"text":"Inhibits reabsorption of sodium chloride in the proximal tubule","correct":false,"visible":false},{"text":"Inhibits reabsorption of sodium and potassium excretion by inhibiting the aldosterone actions","correct":false,"visible":false},{"text":"Inhibits reabsorption of sodium chloride in the ascending limb of the loop of Henle","correct":false,"visible":false},{"text":"Inhibits reabsorption of sodium chloride by inhibiting the carbonic anhydrase enzyme","correct":false,"visible":false}]},{"id":6884,"text":"A 35-year-old male presents with features of nephrotic syndrome. In addition, there is microscopic haematuria. Renal biopsy shows partial sclerosis affecting some of the glomeruli. Sclerosed areas show IgM and C3 on immune fluorescence. What is the most likely diagnosis in this patient?","explanation":null,"reference":null,"responses":[{"text":"IgA nephropathy","correct":false,"visible":false},{"text":"Focal segmental glomerulosclerosis","correct":true,"visible":false},{"text":"Membranous nephropathy","correct":false,"visible":false},{"text":"Minimal change disease","correct":false,"visible":false},{"text":"Acute post infectious glomerulonephritis","correct":false,"visible":false}]},{"id":6885,"text":"A 4-year-old girl presents to the outpatient department with severe pitting edema. Further investigations show hypoalbuminemia, lipiduria, and 3.8 g proteinuria. Biopsy confirms the renal disease. Which of the following best describes the pathophysiology of proteinuria in this patient?","explanation":null,"reference":null,"responses":[{"text":"Crescent formation in the glomeruli","correct":false,"visible":false},{"text":"Derangement in glomerular capillary walls","correct":true,"visible":false},{"text":"Tubulo-interstitial damage","correct":false,"visible":false},{"text":"Anti GBM antibodies cross reacting with alveolar basement membranes","correct":false,"visible":false},{"text":"Excess dietary protein intake","correct":false,"visible":false}]},{"id":6886,"text":"A 40-year-old male presents to the emergency (ER) with colicky lower abdominal pain and hematuria. The attending doctor makes the preliminary diagnosis of urinary tract calculus. To confirm his diagnosis, the first radiological modality is:","explanation":null,"reference":null,"responses":[{"text":"CT KUB","correct":false,"visible":false},{"text":"X-ray pelvis","correct":false,"visible":false},{"text":"X-ray KUB","correct":false,"visible":false},{"text":"Intravenous urogram (IVU)","correct":false,"visible":false},{"text":"Ultrasound pelvis","correct":true,"visible":false}]},{"id":6902,"text":"A 40-year-old female, presented with severe abdominal pain with radiation to her back. Computed tomography (CT) scan showed bilateral ureterolithiasis. Which one of the following is appropriate regarding stones?","explanation":null,"reference":null,"responses":[{"text":"Uric acid stone","correct":false,"visible":false},{"text":"Cystine stone","correct":false,"visible":false},{"text":"Calcium oxalate stone","correct":true,"visible":false},{"text":"Struvite stone","correct":false,"visible":false},{"text":"Calcium phosphate stone","correct":false,"visible":false}]},{"id":6905,"text":"A 40-year-old man has had increasing lower extremity edema for the past three weeks. On examination, his blood pressure (BP) is 135/90 mmHg and pitting edema up till his knees. Laboratory results show serum creatinine level of 1.2 mg/dl and urea nitrogen of 16 mg/dl. 24-hour urine protein of 7.4 grams. Serum ASO, ANA, HIV, and ANCA are negative. Complement levels are also normal. On renal biopsy, there is a diffuse uniform thickening of the glomerular basement membranes. Immunofluorescence shows granular IgG and C3 basement membrane deposits. In the given scenario, electron microscopy would most likely reveal which finding?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 912-914.","responses":[{"text":"Fusion of podocyte foot processes","correct":false,"visible":false},{"text":"Sub-epithelial IgG and C3 deposits electron dense deposits","correct":true,"visible":false},{"text":"Mesangial IgG and C3 electron dense deposits","correct":false,"visible":false},{"text":"Sub-endothelial electron dense deposits with duplication of basement membranes","correct":false,"visible":false},{"text":"No abnormality","correct":false,"visible":false}]},{"id":6906,"text":"A 44-year-old male came for a follow-up checkup with his laboratory results, which showed increased creatinine, urea, and PSA level. The physician suspected benign prostate hypertrophy. What is the most common manifestation of benign prostate hypertrophy?","explanation":null,"reference":null,"responses":[{"text":"Nephrotic syndrome","correct":false,"visible":false},{"text":"Acute pyelonephritis","correct":false,"visible":false},{"text":"Nephritic syndrome","correct":false,"visible":false},{"text":"Hydronephrosis","correct":false,"visible":false},{"text":"Lower urinary tract obstruction","correct":true,"visible":false}]},{"id":6907,"text":"A 44-year-old man complaints of swelling of legs and puffiness around eyes. His abdomen becomes protuberant and he feels shortness of breath. There is generalized edema and ascites. Total serum protein is 5.2 g/dL (range 5.5-8.0) and albumin is 1.9 g/dL (range 3.5-5.5). Serum cholesterol is 530 mg/dL. There are 5 grams of protein in 24-hr urine collection. The urinary sediment contains many hyaline casts but no RBCs or WBCs. Renal biopsy immunofluorescence shows a granular pattern. Which of the following immunologic mechanisms was most likely responsible for glomerular changes?","explanation":null,"reference":null,"responses":[{"text":"Cross-reacting antibodies formed against streptococci","correct":false,"visible":false},{"text":"Cytotoxic T cells directed against renal antigens","correct":false,"visible":false},{"text":"Release of cytokines by inflammatory cells","correct":false,"visible":false},{"text":"Antibodies against basement membrane collagen","correct":false,"visible":false},{"text":"Deposition of immune complexes on basement membrane","correct":true,"visible":false}]},{"id":6909,"text":"A 45-year-old patient with kidney failure was diagnosed with polycystic kidney disease. Both adult and childhood polycystic kidney diseases lead to end-stage renal disease and renal failure requiring dialysis. Which of the following is correct for this disease?","explanation":null,"reference":null,"responses":[{"text":"Mostly appears in childhood","correct":false,"visible":false},{"text":"Autosomal recessive polycystic kidney disease","correct":false,"visible":false},{"text":"Is a disease of women only","correct":false,"visible":false},{"text":"Occurs with the same frequency as autosomal dominant variant","correct":false,"visible":false},{"text":"More commonly appears in the old age","correct":true,"visible":false}]},{"id":6910,"text":"A 48-year-old male with a history of the human immunodeficiency virus (HIV) and obesity has noticed recent fatigue, bilateral pedal edema, and periorbital puffiness. Urine D/R shows proteinuria and fatty casts. If we plan renal biopsy what will be the histological result?","explanation":null,"reference":null,"responses":[{"text":"Rapidly progressive glomerulonephritis (RPGN)","correct":false,"visible":false},{"text":"Hypertensive glomerulosclerosis","correct":false,"visible":false},{"text":"Diabetic nephropathy","correct":false,"visible":false},{"text":"Nephrotic syndrome","correct":true,"visible":false},{"text":"Normal glomeruli","correct":false,"visible":false}]},{"id":6911,"text":"A 5-year-old boy presents to the outpatient department with generalized edema and periorbital edema. Further investigations show hypoalbuminemia, lipiduria, and 3.7 g proteinuria. Which of the following conditions is the most likely cause in this patient?","explanation":null,"reference":null,"responses":[{"text":"Rapidly progressive glomerulonephritis","correct":false,"visible":false},{"text":"Focal segmental glomerulosclerosis","correct":false,"visible":false},{"text":"Minimal change disease","correct":true,"visible":false},{"text":"IgA nephropathy","correct":false,"visible":false},{"text":"Amyloidosis","correct":false,"visible":false}]},{"id":6912,"text":"A 50-year-old man with mild hypertension, treated with spironolactone, complains of discomfort in his chest, and gynecomastia. His physician decides to switch this patient to a drug that has the same mechanism of action but will avoid this adverse effect. Which of the following drugs would he use?","explanation":null,"reference":null,"responses":[{"text":"Amiloride","correct":true,"visible":false},{"text":"Acetazolamide","correct":false,"visible":false},{"text":"Chlorthalidone","correct":false,"visible":false},{"text":"Furosemide","correct":false,"visible":false},{"text":"Torsemide","correct":false,"visible":false}]},{"id":6913,"text":"A 55-year-old patient is admitted with a massive gastrointestinal (GI) bleed. The patient is at risk for what type of acute kidney injury?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 412.","responses":[{"text":"Intrinsic renal","correct":false,"visible":false},{"text":"Para-renal","correct":false,"visible":false},{"text":"Intra-renal","correct":false,"visible":false},{"text":"Post-renal","correct":false,"visible":false},{"text":"Pre-renal","correct":true,"visible":false}]},{"id":6914,"text":"A 58-year-old man noticed blood in his urine and consulted his family physician. On examination, he appears to be in good health. Laboratory results show mild microcytic, hypochromic anemia, and hematuria. X-ray abdomen followed by computed tomography (CT) scan revealed an irregular mass 6 cm in diameter occupying most of his left kidney. Which of the following is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Angiomyolipoma","correct":false,"visible":false},{"text":"Renal papillary adenoma","correct":false,"visible":false},{"text":"Renal cell carcinoma","correct":true,"visible":false},{"text":"Wilms tumor","correct":false,"visible":false},{"text":"Neuroblastoma","correct":false,"visible":false}]},{"id":6916,"text":"A 6-year-old boy presents with generalized edema and periorbital edema. Further investigations show hypoalbuminemia, lipiduria, and 3.6 g proteinuria. Renal biopsy and electron microscopy were carried out. Which of the following electron microscopic features do you expect to find in this patient?","explanation":null,"reference":null,"responses":[{"text":"Loss of foot processes, no deposits","correct":true,"visible":false},{"text":"Subendothelial deposits","correct":false,"visible":false},{"text":"Subepithelial humps","correct":false,"visible":false},{"text":"Linear deposits of IgG in the glomerular basement membrane","correct":false,"visible":false},{"text":"Dense mesangial deposits","correct":false,"visible":false}]},{"id":6920,"text":"A 6-year-old child presented to the emergency department (ED) with complaints of abdominal pain and vomiting. He was previously healthy but has a history of easy fatigability, weight loss, and increased thirst. On examination, heart rate is 145/min, respiratory rate 50/min, temperature 98F, and the chest is clear on auscultation. On investigations, arterial blood gases (ABGs) showed pH 7.2, and HCO3 12 meq/l. The random blood sugar is 360 mg/dl. What is the likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Acute renal failure","correct":false,"visible":false},{"text":"Diabetic ketoacidosis","correct":true,"visible":false},{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Congenital adrenal hyperplasia","correct":false,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false}]},{"id":6921,"text":"A 6-year-old girl develops pitting edema in her ankles and legs. Urinalysis show 3+ proteinuria. The urinary sediment contains no inflammatory cells or red blood cells. Serum levels of blood urea nitrogen (BUN) and creatinine are normal. She recovers completely after a course of corticosteroids. Light microscopy of a renal biopsy specimen from this girl would most likely demonstrate which of the following changes?","explanation":null,"reference":null,"responses":[{"text":"Fusion of podocyte foot processes","correct":false,"visible":false},{"text":"Duplication of capillary basement membranes","correct":false,"visible":false},{"text":"Loss of microvilli by the tubular lining cells","correct":false,"visible":false},{"text":"Electron-dense immune deposits in the capillary basement membranes","correct":false,"visible":false},{"text":"No visible abnormality","correct":true,"visible":false}]},{"id":6923,"text":"A 62-year-old female complains of pain in her right flank. There is tenderness at the right costo-vertebral angle. Laboratory tests show microscopic hematuria but no protein or glucose. Complete blood count (CBC) shows microcytic and hypochromic anemia. Computed tomography (CT) scan reveals an irregular renal mass 5.2 cm in diameter occupying the upper pole of the right kidney. A biopsy is performed and histology shows atypical cells with pleomorphic nuclei and abundant clear cytoplasm. Molecular studies in this patient would most likely identify mutations in which of the following genes?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 953.","responses":[{"text":"p53","correct":false,"visible":false},{"text":"WT1","correct":false,"visible":false},{"text":"IGF-2","correct":false,"visible":false},{"text":"VHL","correct":true,"visible":false},{"text":"Rb","correct":false,"visible":false}]},{"id":6924,"text":"A 65-year-old male came with the presenting complaints of dysuria, frequency, and urgency. He had a history of right renal transplant. Urine culture showed growth of E. coli. The X-ray showed a contracted kidney with blunting and deformity of the calyces. What would be the diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Nephritic syndrome","correct":false,"visible":false},{"text":"Nephrotic syndrome","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Pyelonephritis","correct":true,"visible":false},{"text":"Renal stones","correct":false,"visible":false}]},{"id":6925,"text":"A 66-year-old male presented with the complaint of complete anuria and pain in the groin region. X-ray showed stone below the level of ureters. What would be the diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Hydronephrosis due to unilateral complete obstruction","correct":false,"visible":false},{"text":"Hydronephrosis due to bilateral complete obstruction","correct":true,"visible":false},{"text":"Hydronephrosis due to unilateral partial obstruction","correct":false,"visible":false},{"text":"Hydronephrosis due to bilateral partial obstruction","correct":false,"visible":false},{"text":"Hydronephrosis due to impaired vesicoureteral reflux","correct":false,"visible":false}]},{"id":6926,"text":"A 70-year-old female came to the emergency for dysuria and hematuria. Urine D/R showed numerous pus cells and proteinuria. X-ray showed an asymmetrical contracted kidney with blunting of the calyceal system. She was diagnosed with reflux nephropathy. Which one of the following complications is associated with reflux nephropathy?","explanation":null,"reference":null,"responses":[{"text":"Glomerulosclerosis","correct":false,"visible":false},{"text":"Renal tumors","correct":false,"visible":false},{"text":"Hydronephrosis","correct":true,"visible":false},{"text":"Nephritic syndrome","correct":false,"visible":false},{"text":"Pyonephrosis","correct":false,"visible":false}]},{"id":6927,"text":"A 70-year-old male presented with complaints of pain in the groin, hematuria, and anuria. Ultrasound showed unilateral obstruction with dilated pelvis and calyces. The physician diagnosed him with a case of hydronephrosis. What is the site of obstruction?","explanation":null,"reference":null,"responses":[{"text":"In collecting tubules","correct":false,"visible":false},{"text":"At renal pelvis","correct":false,"visible":false},{"text":"In renal medulla","correct":false,"visible":false},{"text":"Below ureter","correct":false,"visible":false},{"text":"At ureter","correct":true,"visible":false}]},{"id":6928,"text":"A child was recently diagnosed with nephrotic syndrome on renal biopsy. Her mother asked how she can identify a relapse. Sign of relapse is:","explanation":null,"reference":null,"responses":[{"text":"Weight loss","correct":false,"visible":false},{"text":"Jaundice","correct":false,"visible":false},{"text":"Weight gain","correct":false,"visible":false},{"text":"Swelling in legs, hands, face or abdomen","correct":true,"visible":false},{"text":"Tea-colored urine","correct":false,"visible":false}]},{"id":6934,"text":"A couple married for four years was unable to conceive a pregnancy. A detailed analysis of the sperms of the husband revealed azoospermia. They were suggested to go for artificial insemination by a fertility specialist. Which type of procedure would best suit the couple?","explanation":null,"reference":null,"responses":[{"text":"Artificial insemination","correct":false,"visible":false},{"text":"Artificial insemination homologous","correct":false,"visible":false},{"text":"In vitro fertilization","correct":false,"visible":false},{"text":"Artificial insemination donor","correct":true,"visible":false},{"text":"Surrogacy","correct":false,"visible":false}]},{"id":6935,"text":"A couple married for three years was unable to conceive a child. Laboratory reports for fertility analysis were found to be normal for both the husband (age = 35 years) and wife (age = 29 years) with no known comorbidities. What procedure will you advise them to consider?","explanation":null,"reference":null,"responses":[{"text":"Artificial insemination homologous","correct":true,"visible":false},{"text":"Artificial insemination","correct":false,"visible":false},{"text":"In vitro fertilization","correct":false,"visible":false},{"text":"Surrogacy","correct":false,"visible":false},{"text":"Artificial insemination donor","correct":false,"visible":false}]},{"id":6936,"text":"A diagnosed patient of the nephritic syndrome will complain of:","explanation":null,"reference":null,"responses":[{"text":"Oliguria","correct":true,"visible":false},{"text":"Anuria","correct":false,"visible":false},{"text":"Dysuria","correct":false,"visible":false},{"text":"Polyuria","correct":false,"visible":false},{"text":"Glycosuria","correct":false,"visible":false}]},{"id":6937,"text":"A female rape victim is brought by police to the medico-legal section for examination. What is the first step you will take before starting the examination?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 372.","responses":[{"text":"Note marks of identification","correct":false,"visible":false},{"text":"Take written consent of victim","correct":false,"visible":false},{"text":"Ensure privacy","correct":false,"visible":false},{"text":"Note personal data","correct":false,"visible":false},{"text":"Ask for authority letter","correct":true,"visible":false}]},{"id":6938,"text":"A middle-aged female was advised ultrasound KUB for recurrent abdominal pain. All of the following are the clinical indications for ultrasound except:","explanation":null,"reference":null,"responses":[{"text":"Evaluate renal function","correct":true,"visible":false},{"text":"Diagnosis of renal and bladder masses","correct":false,"visible":false},{"text":"Detection of urinary tract calculi","correct":false,"visible":false},{"text":"Assess renal parenchymal changes","correct":false,"visible":false},{"text":"Diagnosis of congenital anomalies","correct":false,"visible":false}]},{"id":6939,"text":"A middle-aged man with a history of gross hematuria for 2 weeks. He had an ultrasound KUB which gave suspicion of a left renal mass lesion. Which is the next imaging modality for confirmation and staging of the renal mass lesion?","explanation":null,"reference":null,"responses":[{"text":"CT abdomen and pelvis with contrast","correct":true,"visible":false},{"text":"MRI abdomen with contrast","correct":false,"visible":false},{"text":"CT angiography","correct":false,"visible":false},{"text":"CT KUB","correct":false,"visible":false},{"text":"MRI abdomen without contrast","correct":false,"visible":false}]},{"id":6940,"text":"A patient taking aminoglycosides was prescribed one of these diuretics, then the patient experienced hearing loss and damage to the ear. Which drug did he take?","explanation":null,"reference":null,"responses":[{"text":"Spironolactone","correct":false,"visible":false},{"text":"Chlorothiazide","correct":false,"visible":false},{"text":"Acetazolamide","correct":false,"visible":false},{"text":"Furosemide","correct":true,"visible":false},{"text":"Hydrochlorothiazide","correct":false,"visible":false}]},{"id":6946,"text":"A radiologist while observing an X-ray of the abdomen observe a soft tissue shadow extending from the spinous process of the L1 vertebra to the posterior superior iliac spine that intersects the tip of the transverse process of the lumbar vertebrae. The appropriate structure observed by radiologists is:","explanation":null,"reference":null,"responses":[{"text":"Ureter","correct":true,"visible":false},{"text":"Ascending colon","correct":false,"visible":false},{"text":"Descending colon","correct":false,"visible":false},{"text":"Renal pelvis","correct":false,"visible":false},{"text":"Fallopian tube","correct":false,"visible":false}]},{"id":6949,"text":"A sonologist while doing a color Doppler examination of arteries in hypertensive patients,  visualized an artery extending from the intervertebral disc between L1 and L2 vertebra approximately 5 cm from the median plane in the transpyloric plane. Appropriate artery visualize by sinologist is:","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 267.","responses":[{"text":"Hepatic","correct":false,"visible":false},{"text":"Left gastric","correct":false,"visible":false},{"text":"Coeliac","correct":false,"visible":false},{"text":"Renal","correct":true,"visible":false},{"text":"Inferior mesenteric","correct":false,"visible":false}]},{"id":6954,"text":"According to Pakistani law, abortion is justified only in which condition?","explanation":null,"reference":null,"responses":[{"text":"To save the life of the mother","correct":true,"visible":false},{"text":"If it is performed by a trained doctor","correct":false,"visible":false},{"text":"For socioeconomic reason","correct":false,"visible":false},{"text":"In a woman with large family","correct":false,"visible":false},{"text":"In a case of unmarried women","correct":false,"visible":false}]},{"id":6956,"text":"According to the hudood ordinance, what is the punishment of Zina liable to Hudd when both male and female are muhsan?","explanation":null,"reference":null,"responses":[{"text":"Five years imprisonment","correct":false,"visible":false},{"text":"10 years imprisonment","correct":false,"visible":false},{"text":"Stoned to death","correct":true,"visible":false},{"text":"Hundreds strips","correct":false,"visible":false},{"text":"Fine not exceeding ten thousand rupees","correct":false,"visible":false}]},{"id":6958,"text":"A victim of sexual assault was brought by police to the medico-legal section for examination. On examination, the anal orifice was dilated and tender to touch, abrasions were present between the anus and tip of the coccyx. The victim was subjected to which of the following sexual offense?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 389.","responses":[{"text":"Tribadism","correct":false,"visible":false},{"text":"Sadism","correct":false,"visible":false},{"text":"Rape","correct":false,"visible":false},{"text":"Sodomy","correct":true,"visible":false},{"text":"Bestiality","correct":false,"visible":false}]},{"id":6963,"text":"Which of the following is correct for acute epididymo-orchitis?","explanation":null,"reference":null,"responses":[{"text":"Is usually caused by gonorrhea","correct":true,"visible":false},{"text":"Invariably responds rapidly to treatment","correct":false,"visible":false},{"text":"In elderly it is often associated with bladder out flow obstruction","correct":false,"visible":false},{"text":"Is best treated with metronidazole","correct":false,"visible":false},{"text":"Is always clinically distinguishable from testicular torsion","correct":false,"visible":false}]},{"id":6964,"text":"After delivery, the uterus returns to its normal size in:","explanation":null,"reference":null,"responses":[{"text":"6 weeks","correct":true,"visible":false},{"text":"1 week","correct":false,"visible":false},{"text":"3 weeks","correct":false,"visible":false},{"text":"4 weeks","correct":false,"visible":false},{"text":"10 days","correct":false,"visible":false}]},{"id":6966,"text":"After examination of a rape victim, a vaginal swab is collected and sent to the laboratory to detect the presence of seminal fluid. Which test is used to detect seminal fluid even in absence of spermatozoa?","explanation":null,"reference":null,"responses":[{"text":"Florence test","correct":false,"visible":false},{"text":"Creatinine phosphokinase test","correct":false,"visible":false},{"text":"Acid phosphatase test","correct":true,"visible":false},{"text":"Precipitin test","correct":false,"visible":false},{"text":"Cell microscopy","correct":false,"visible":false}]},{"id":6967,"text":"A dead body of a girl was brought for autopsy. On examination, she was pregnant, and severe injuries were observed in her pelvic area. On inquiry, her mother told that she tried to criminally induce abortion during which she died within minutes. What is the most probable cause of death?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 340.","responses":[{"text":"Vagal inhibition","correct":true,"visible":false},{"text":"Septicemia","correct":false,"visible":false},{"text":"Secondary hemorrhage","correct":false,"visible":false},{"text":"Renal Failure","correct":false,"visible":false},{"text":"Peritonitis","correct":false,"visible":false}]},{"id":6968,"text":"All following statements about renal stones are incorrect except?","explanation":null,"reference":null,"responses":[{"text":"A staghorn calculus is composed of calcium-uric acid-magnesium phosphate","correct":false,"visible":false},{"text":"Pure uric acid stones are radio-lucent","correct":true,"visible":false},{"text":"If a parathyroid adenoma is found to be the cause of renal calculi, it should not be removed before treatment of the calculus","correct":false,"visible":false},{"text":"Hyperparathyroidism is found in 50 per cent of those presenting with radio-opaque calculi","correct":false,"visible":false},{"text":"The common bacteria found as a nidus for urinary stones are Streptococci and Pseudomonas","correct":false,"visible":false}]},{"id":6970,"text":"Amima has recently completed her FCPS and now she is pursuing her career as a specialist. She was passionate about this field and always wanted to serve society and live a meaningful life. The approach of happiness focuses on meaning and self-realization. In view of which terms of the degree a person is fully functioning hedonism?","explanation":null,"reference":null,"responses":[{"text":"Objective well being","correct":false,"visible":false},{"text":"Eudemonia","correct":false,"visible":false},{"text":"Subjective well being","correct":true,"visible":false},{"text":"Happiness","correct":false,"visible":false},{"text":"Psychological well being","correct":false,"visible":false}]},{"id":6971,"text":"An 11-year old boy presents with the complaint of swelling in his feet for the past 4 weeks. He is otherwise in good health and gives no previous history of any illness. Physical examination reveals pitting edema of the lower legs and a swollen abdomen. Urinalysis shows 4+ protein but no RBCs or WBCs.The treating physicians should consider which of the following conditions in this case?","explanation":null,"reference":"Kumar, Vinay, et al. Robbins and Cotran Pathologic Basis of Disease. 9th ed., Elsevier Saunders, 2015:  917.","responses":[{"text":"Renal cell carcinoma","correct":false,"visible":false},{"text":"Minimal change disease","correct":true,"visible":false},{"text":"Pyelonephritis with acute tubular necrosis","correct":false,"visible":false},{"text":"Post-streptococcal glomerulonephritis","correct":false,"visible":false},{"text":"Wilms tumor","correct":false,"visible":false}]},{"id":6972,"text":"Benign prostatic hyperplasia (BPH) is an extremely common cause of prostatic enlargement resulting from the proliferation of stromal and glandular elements. The glandular lumina contains inspissated proteinaceous secretory material. The secretory material is known as:","explanation":null,"reference":null,"responses":[{"text":"Corpora amylacea","correct":true,"visible":false},{"text":"Corpora cavernosa","correct":false,"visible":false},{"text":"Corpora arenacea","correct":false,"visible":false},{"text":"Corpora cardiaca","correct":false,"visible":false},{"text":"Corpora spongiosum","correct":false,"visible":false}]},{"id":6973,"text":"Which of the following is correct for carcinoma of the prostate?","explanation":null,"reference":null,"responses":[{"text":"Is typically a squamous cell carcinoma","correct":false,"visible":false},{"text":"Is graded histologically using the Gleason score","correct":true,"visible":false},{"text":"Occurs predominantly in the central zone of the prostate","correct":false,"visible":false},{"text":"Causes rectal compression","correct":false,"visible":false},{"text":"Is not influenced by hormone manipulation","correct":false,"visible":false}]},{"id":6974,"text":"Dietary restriction in nephrotic syndrome includes a low-sodium diet and:","explanation":null,"reference":null,"responses":[{"text":"High-carbohydrate","correct":false,"visible":false},{"text":"Low-potassium","correct":false,"visible":false},{"text":"Low-iron","correct":false,"visible":false},{"text":"Low-fat","correct":true,"visible":false},{"text":"Low-phosphate","correct":false,"visible":false}]},{"id":6975,"text":"For up-to-date information, the best source in research is:","explanation":null,"reference":null,"responses":[{"text":"Books","correct":false,"visible":false},{"text":"Conference proceedings","correct":false,"visible":false},{"text":"Newspapers","correct":false,"visible":false},{"text":"Monographs","correct":false,"visible":false},{"text":"Scientific journals","correct":true,"visible":false}]},{"id":6976,"text":"Fornication under law means:","explanation":null,"reference":null,"responses":[{"text":"When the women of 21 years age have consented for the act under threat of death","correct":false,"visible":false},{"text":"Forced sexual intercourse by a woman with a man","correct":false,"visible":false},{"text":"Sexual intercourse by a women of a body under 14 years of age","correct":false,"visible":false},{"text":"Sexual intercourse with a woman, when the offends knows that he is not her husband","correct":false,"visible":false},{"text":"Willful sexual intercourse between man and women who are not married to each other","correct":true,"visible":false}]},{"id":6977,"text":"Two adult males were convicted in the court of law for an offense of sodomy. What is the most suggestive evidence of sodomy?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 390.","responses":[{"text":"Loss of rugosity of anal mucosa","correct":false,"visible":false},{"text":"Presence of semen in anal canal","correct":true,"visible":false},{"text":"Radial fissure of mucous membrane of anus","correct":false,"visible":false},{"text":"Bruising present around anal orifice","correct":false,"visible":false},{"text":"Dilatation of anal canal","correct":false,"visible":false}]},{"id":6978,"text":"Furosemide acts by inhibiting which of the following in the renal tubular cell?","explanation":null,"reference":null,"responses":[{"text":"Na+-K+-2Cl– cotransporter","correct":true,"visible":false},{"text":"Na+-Cl– symporter","correct":false,"visible":false},{"text":"Na+-K+-ATPase","correct":false,"visible":false},{"text":"Na+-H+ antiporter","correct":false,"visible":false},{"text":"Na+-H+-K+-symporter","correct":false,"visible":false}]},{"id":6979,"text":"Glomerular filtration depends upon the renal blood flow. To achieve the normal glomerular filtration rate (GFR) of 180 L/day, the fraction of renal plasma flow that is filtered averages about:","explanation":null,"reference":null,"responses":[{"text":"10%","correct":false,"visible":false},{"text":"40%","correct":false,"visible":false},{"text":"05%","correct":false,"visible":false},{"text":"20%","correct":true,"visible":false},{"text":"30%","correct":false,"visible":false}]},{"id":6980,"text":"How does testicular torsion typically present?","explanation":null,"reference":null,"responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Sudden pain in the scrotum and an absent cremasteric reflex","correct":true,"visible":false},{"text":"Sudden pain in the scrotum but preserved cremasteric reflex","correct":false,"visible":false},{"text":"Sudden pain in the scrotum and gross hematuria","correct":false,"visible":false},{"text":"Swelling of scrotum and fever","correct":false,"visible":false}]},{"id":6982,"text":"Laboratory diagnosis is based on colony counts following culture, which reflect the concentration of organisms in urine and hence the likelihood that the bacteria have grown arise from a urinary tract infection (UTI) rather than contamination. What would be the minimum urine culture colony count necessary to make a clinical diagnosis of UTI?","explanation":null,"reference":null,"responses":[{"text":"100,000 -200,000 CFU/ml","correct":true,"visible":false},{"text":"10,000-50,000 CFU/ml","correct":false,"visible":false},{"text":"50,000 -100,000 CFU/ml","correct":false,"visible":false},{"text":"1000-10,000 CFU/ml","correct":false,"visible":false},{"text":"100-1000 CFU/ml","correct":false,"visible":false}]},{"id":6983,"text":"Left ventricular hypertrophy in chronic kidney disease patients can occur due to:","explanation":null,"reference":null,"responses":[{"text":"Vitamin D deficiency","correct":false,"visible":false},{"text":"Vitamin C deficiency","correct":false,"visible":false},{"text":"Hypercalcemia","correct":false,"visible":false},{"text":"Hypertension","correct":true,"visible":false},{"text":"Hyperphosphatemia","correct":false,"visible":false}]},{"id":6984,"text":"Mechanism of action of tamsulosin:","explanation":null,"reference":null,"responses":[{"text":"Alpha-2 receptor blocker","correct":false,"visible":false},{"text":"B1-receptor blocker","correct":false,"visible":false},{"text":"Alpha-2 receptor agonist","correct":false,"visible":false},{"text":"Alpha-1 receptor blocker","correct":true,"visible":false},{"text":"Phosphodiesterase 5 inhibitor","correct":false,"visible":false}]},{"id":6985,"text":"Nephrotic range proteinuria is generally considered:","explanation":null,"reference":null,"responses":[{"text":"Greater than 3.5 gm/day","correct":true,"visible":false},{"text":"Greater than 7.4 gm/day","correct":false,"visible":false},{"text":"Greater than 5.0 gm/day","correct":false,"visible":false},{"text":"Greater than 2.0 gm/day","correct":false,"visible":false},{"text":"Greater than 1.0 gm/day","correct":false,"visible":false}]},{"id":6986,"text":"Parents brought a 7-year-old child to emergency with a history of passing cola-colored urine since morning and severe headache for the last 2 hours. There is a history of skin infection 15 days back, which was treated by some local general practitioner (GP). Which is the most important vital sign examination in this child?","explanation":null,"reference":null,"responses":[{"text":"Respiratory rate","correct":false,"visible":false},{"text":"O2 saturation","correct":false,"visible":false},{"text":"Heart rate","correct":false,"visible":false},{"text":"Temperature","correct":false,"visible":false},{"text":"Blood pressure","correct":true,"visible":false}]},{"id":6988,"text":"Patients with progressive chronic renal failure typically develop:","explanation":null,"reference":null,"responses":[{"text":"Macrocytic anemia","correct":false,"visible":false},{"text":"Hypochromic microcytic anemia","correct":false,"visible":false},{"text":"Normocytic anemia","correct":true,"visible":false},{"text":"Hemolytic anemia","correct":false,"visible":false},{"text":"Aplastic anemia","correct":false,"visible":false}]},{"id":6990,"text":"Regarding renal stones, all of the following are true except:","explanation":null,"reference":null,"responses":[{"text":"The severity of pain of ureteric colic is related to the size of stone","correct":true,"visible":false},{"text":"Hematuria is common","correct":false,"visible":false},{"text":"Hydronephrosis and/or pyonephrosis with a palpable loin swelling is uncommon","correct":false,"visible":false},{"text":"There are very few physical signs","correct":false,"visible":false},{"text":"Renal stones are usually visible on a plain X-ray","correct":false,"visible":false}]},{"id":6992,"text":"Law considers it rape if consenting women had sexual intercourse without marriage, before attaining the age of?","explanation":null,"reference":null,"responses":[{"text":"15 years","correct":false,"visible":false},{"text":"16 years","correct":true,"visible":false},{"text":"18 years","correct":false,"visible":false},{"text":"14 years","correct":false,"visible":false},{"text":"17 years","correct":false,"visible":false}]},{"id":6993,"text":"A research hypothesis is a logical supposition that something is true. A hypothesis is:","explanation":null,"reference":null,"responses":[{"text":"Null hypothesis states that there is an association between two factors/variables","correct":false,"visible":false},{"text":"A statement of the research question in a measurable form","correct":true,"visible":false},{"text":"Hypothesis is required for qualitative research","correct":false,"visible":false},{"text":"A hypothesis is either rejected or accepted","correct":false,"visible":false},{"text":"Alternative hypothesis states that there is a difference in between two factors/variables","correct":false,"visible":false}]},{"id":6995,"text":"Mr. Mughees did not score well in the exam; he has pessimistic explanatory styles and attributed his failure to generalized bad luck i.e. I always had bad luck in all life situations (stable and global attribution), which lead to him being depressed. Which one of the following could preferably explain the causes of negative events contrary to this pessimistic explanatory style?","explanation":null,"reference":null,"responses":[{"text":"Internal, stable","correct":false,"visible":false},{"text":"External, global , stable","correct":false,"visible":false},{"text":"Internal, specific , unstable","correct":true,"visible":false},{"text":"Internal, external, global","correct":false,"visible":false},{"text":"External, unstable , specific","correct":false,"visible":false}]},{"id":6996,"text":"Research is an art of scientific inquiry or investigation and conducted to:","explanation":null,"reference":null,"responses":[{"text":"Discover new facts through guess work","correct":false,"visible":false},{"text":"Find the answer which is obvious","correct":false,"visible":false},{"text":"Make conclusion to best of our intuition","correct":false,"visible":false},{"text":"Establish facts and reach to the new conclusions","correct":true,"visible":false},{"text":"Problem we want to resolve","correct":false,"visible":false}]},{"id":6998,"text":"Resection of an abdominal mass discovered incidentally in a 10-month-old infant by his mother reveals a 10.5 cm well-circumscribed right renal tumor, which is soft in consistency. On slicing, the tumor a pale gray solid surface is noted with cystic areas, necrosis, and hemorrhage. Microscopically, the tumor is composed of blastemal, stromal, and epithelial tissues. Which of the following is the most probable diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 134.","responses":[{"text":"Oncocytoma","correct":false,"visible":false},{"text":"Neuroblastoma","correct":false,"visible":false},{"text":"Wilms tumor","correct":true,"visible":false},{"text":"Renal cell carcinoma","correct":false,"visible":false},{"text":"Papillary adenoma","correct":false,"visible":false}]},{"id":7109,"text":"Sacher Masoch was an Australian novelist. In his novels, he described characters who obtain sexual gratification when they receive a painful stimulus. This type of sexual perversion is called:","explanation":null,"reference":"Sexual masochism disorder - mental health disorders. MSD Manual Consumer Version. Accessed October 24, 2022. https://www.msdmanuals.com/home/mental-health-disorders/paraphilias-and-paraphilic-disorders/sexual-masochism-disorder","responses":[{"text":"Fetichism","correct":false,"visible":false},{"text":"Sadism","correct":false,"visible":false},{"text":"Eonism","correct":false,"visible":false},{"text":"Uranism","correct":false,"visible":false},{"text":"Masochism","correct":true,"visible":false}]},{"id":7111,"text":"Select the diuretic that can cause gynecomastia, hirsutism, and menstrual disturbance as a side effect on long-term use:","explanation":null,"reference":null,"responses":[{"text":"Furosemide","correct":false,"visible":false},{"text":"Amiloride","correct":false,"visible":false},{"text":"Metolazone","correct":false,"visible":false},{"text":"Acetazolamide","correct":false,"visible":false},{"text":"Spironolactone","correct":true,"visible":false}]},{"id":7112,"text":"The filtered fluid from the glomerulus called filtrate consists of the same contents of plasma but it is devoid of the following:","explanation":null,"reference":null,"responses":[{"text":"Urea","correct":false,"visible":false},{"text":"Red blood cells","correct":true,"visible":false},{"text":"Amino acids","correct":false,"visible":false},{"text":"Creatinine","correct":false,"visible":false},{"text":"Glucose","correct":false,"visible":false}]},{"id":7113,"text":"The glomerular filtration rate (GFR) is labeled as an end-stage renal disease (ESRD) at which rate?","explanation":null,"reference":null,"responses":[{"text":"20 ml/min or less","correct":false,"visible":false},{"text":"25 ml/min or less","correct":false,"visible":false},{"text":"15 ml/min or less","correct":true,"visible":false},{"text":"10 ml/min or less","correct":false,"visible":false},{"text":"75 ml/min or less","correct":false,"visible":false}]},{"id":7114,"text":"The leading cause of death among patients with an end-stage renal disease (ESRD) is:","explanation":null,"reference":null,"responses":[{"text":"Uremia","correct":false,"visible":false},{"text":"Liver failure","correct":false,"visible":false},{"text":"Jaundice","correct":false,"visible":false},{"text":"Cardiovascular complication","correct":true,"visible":false},{"text":"Anemia","correct":false,"visible":false}]},{"id":7115,"text":"The major blood supply to testis comes through the:","explanation":null,"reference":null,"responses":[{"text":"Hypogastric arteries","correct":false,"visible":false},{"text":"Internal spermatic arteries","correct":true,"visible":false},{"text":"External spermatic arteries","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Pudendal arteries","correct":false,"visible":false}]},{"id":7116,"text":"The most common systemic disease causing end-stage renal disease globally is:","explanation":null,"reference":null,"responses":[{"text":"Polycystic kidney disease","correct":false,"visible":false},{"text":"Amyloidosis","correct":false,"visible":false},{"text":"All causes of renal vasculitis (e.g., Wegener’s)","correct":false,"visible":false},{"text":"Kidney stone disease","correct":false,"visible":false},{"text":"Diabetes mellitus","correct":true,"visible":false}]},{"id":7119,"text":"The most ominous sign or symptom of the urinary disease is:","explanation":null,"reference":null,"responses":[{"text":"Hematuria","correct":true,"visible":false},{"text":"Pneumaturia","correct":false,"visible":false},{"text":"Dysuria","correct":false,"visible":false},{"text":"Urinary frequency","correct":false,"visible":false},{"text":"Pyuria","correct":false,"visible":false}]},{"id":7120,"text":"The research goal and objectives must be stated at the very beginning of the study. What is the purpose of defining objectives?","explanation":null,"reference":null,"responses":[{"text":"Remain focused on research study","correct":true,"visible":false},{"text":"Formulating hypothesis","correct":false,"visible":false},{"text":"Reach to conclusion","correct":false,"visible":false},{"text":"Formulate research questions","correct":false,"visible":false},{"text":"Compare research findings","correct":false,"visible":false}]},{"id":7121,"text":"The two leading causes of end-stage renal disease (ESRD) are:","explanation":null,"reference":null,"responses":[{"text":"Allergies and diabetes","correct":false,"visible":false},{"text":"Infection and hypertension","correct":false,"visible":false},{"text":"Infection and diabetes","correct":false,"visible":false},{"text":"Allergies and infection","correct":false,"visible":false},{"text":"Diabetes and hypertension","correct":true,"visible":false}]},{"id":7122,"text":"The type of consent recommended for examining doctors to take from the women victim of sexual assault is:","explanation":null,"reference":null,"responses":[{"text":"Expressed written","correct":false,"visible":false},{"text":"Expressed oral","correct":false,"visible":false},{"text":"Blanket","correct":false,"visible":false},{"text":"Implied","correct":false,"visible":false},{"text":"Informed written","correct":true,"visible":false}]},{"id":7123,"text":"Ultrasound has many advantages, which include all of the following except:","explanation":null,"reference":null,"responses":[{"text":"It can be safely performed in pregnant women","correct":false,"visible":false},{"text":"It allows discrimination between pseudotumor and true lesions","correct":true,"visible":false},{"text":"It is not affected by renal function","correct":false,"visible":false},{"text":"It is safe and does not use ionizing radiation","correct":false,"visible":false},{"text":"It required little or no pre-procedural preparation","correct":false,"visible":false}]},{"id":7124,"text":"Ultrasound shows a bright, highly reflective lesion in the right kidney. The most likely diagnosis is:","explanation":null,"reference":null,"responses":[{"text":"Papillary necrosis","correct":false,"visible":false},{"text":"Renal cell carcinoma","correct":false,"visible":false},{"text":"Simple renal cyst","correct":false,"visible":false},{"text":"Renal calculus","correct":true,"visible":false},{"text":"Angiomyolipoma","correct":false,"visible":false}]},{"id":7125,"text":"Which of the following is correct for ureteral obstruction (unilateral)?","explanation":null,"reference":null,"responses":[{"text":"Is associated with hematuria","correct":false,"visible":false},{"text":"Is commonly caused by a urinary tract calculus","correct":true,"visible":false},{"text":"Is associated with increase in urea and creatinine","correct":false,"visible":false},{"text":"Usually requires open surgical relief of the obstruction","correct":false,"visible":false},{"text":"Is usually associated with infection behind the obstruction","correct":false,"visible":false}]},{"id":7126,"text":"Which of the following is correct for uric acid calculi?","explanation":null,"reference":null,"responses":[{"text":"Occurs less frequently after treatment with penicillamine","correct":false,"visible":false},{"text":"Are typical well demonstrated by CT scan","correct":true,"visible":false},{"text":"Can be dissolved by treatment with allopurinol","correct":false,"visible":false},{"text":"Are the most common upper tract calculi","correct":false,"visible":false},{"text":"Are characteristically radio-opaque","correct":false,"visible":false}]},{"id":7127,"text":"Voiding urinary symptoms include all about except:","explanation":null,"reference":null,"responses":[{"text":"Straining","correct":false,"visible":false},{"text":"Hesitancy","correct":false,"visible":false},{"text":"Reduced (poor) stream","correct":false,"visible":false},{"text":"Frequency","correct":true,"visible":false},{"text":"Feeling of incomplete emptying of urinary bladder","correct":false,"visible":false}]},{"id":7128,"text":"What is hypospadias?","explanation":null,"reference":null,"responses":[{"text":"Inflammation of the testicles","correct":false,"visible":false},{"text":"Benign warty growth on genital skin","correct":false,"visible":false},{"text":"Opening of urethra on the ventral surface of penis","correct":true,"visible":false},{"text":"Opening of urethra on the dorsal surface of penis","correct":false,"visible":false},{"text":"Dilatation and tortuosity of pampiniform plexus","correct":false,"visible":false}]},{"id":7129,"text":"What would be the first step in the sequence of steps to be followed while conducting research?","explanation":null,"reference":null,"responses":[{"text":"Literature search","correct":false,"visible":false},{"text":"Formulate research question","correct":true,"visible":false},{"text":"Analysis","correct":false,"visible":false},{"text":"Selection of setting/area","correct":false,"visible":false},{"text":"Compare findings","correct":false,"visible":false}]},{"id":7130,"text":"Which of the following is not a classical feature of the nephrotic syndrome?","explanation":null,"reference":null,"responses":[{"text":"Hypoalbuminemia","correct":false,"visible":false},{"text":"Peripheral edema","correct":false,"visible":false},{"text":"Hypercholesterolemia","correct":false,"visible":false},{"text":"Proteinuria greater than 3.5 g/ day","correct":false,"visible":false},{"text":"Microscopic hematuria","correct":true,"visible":false}]},{"id":7131,"text":"Which patient below is NOT at risk for developing nephrotic syndrome?","explanation":null,"reference":null,"responses":[{"text":"A 58-year-old male with diabetes mellitus","correct":false,"visible":false},{"text":"A 7-year-old male recently diagnosed with Alport syndrome","correct":true,"visible":false},{"text":"A 60-year-old male with diabetes mellitus","correct":false,"visible":false},{"text":"A 40-year-old male with lupus","correct":false,"visible":false},{"text":"A 5-year-old female diagnosed with minimal change disease","correct":false,"visible":false}]},{"id":7132,"text":"You're collecting a urine sample on a patient who is experiencing proteinuria due to nephrotic syndrome. As the doctor, you know the urine will appear:","explanation":null,"reference":null,"responses":[{"text":"Orange and frothy","correct":true,"visible":false},{"text":"Tea-colored","correct":false,"visible":false},{"text":"Dark and foamy","correct":false,"visible":false},{"text":"Straw-colored","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":7510,"text":"A 23-year-old female, who is a known case of anxiety disorder, begins hyperventilating while waiting to see her psychiatrist. The doctor's assistant immediately makes her breathe in a paper bag and she improves. If an arterial blood gas was taken while she was hyperventilating it would have probably which of the following findings?","explanation":null,"reference":null,"responses":[{"text":"Decreased pH and increased PCO2","correct":false,"visible":false},{"text":"Decreased pH and decreased PCO2","correct":false,"visible":false},{"text":"Increased pH and increased PCO2","correct":false,"visible":false},{"text":"Normal findings on arterial blood gas","correct":false,"visible":false},{"text":"Increased pH and decreased PCO2","correct":true,"visible":false}]},{"id":7513,"text":"A 67-year-old male who is a known case of chronic renal failure (CRF) comes for his follow-up visit to the nephrologist. His creatinine is stable, however, his bicarbonate is 15 mEq/L. In order to prevent metabolic bone disease, his serum bicarbonate levels should be maintained at what level?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 418.","responses":[{"text":"\u003e 25 mEq","correct":false,"visible":false},{"text":"\u003c 10 mEq","correct":false,"visible":false},{"text":"\u003c 21 mEq","correct":false,"visible":false},{"text":"\u003c40 others","correct":false,"visible":false},{"text":"\u003e 21 mEq","correct":true,"visible":false}]},{"id":7598,"text":"A 36-year-old female presents to the emergency with a high-grade fever with chills, increased urination, and one episode of hematuria. On examination, she has tenderness in the right lumbar region. What is the most likely cause of her illness?","explanation":null,"reference":null,"responses":[{"text":"Acute salpingitis","correct":false,"visible":false},{"text":"Urethritis","correct":false,"visible":false},{"text":"Acute pyelonephritis","correct":true,"visible":false},{"text":"Nephrolithiasis","correct":false,"visible":false},{"text":"Pelvic inflammatory disease","correct":false,"visible":false}]},{"id":7600,"text":"An ultrasound scan of a pregnant woman revealed a large bladder in a fetus (mega cystitis). It is also associated with dilation of the renal pelvis. What is the embryological basis of this anomaly?","explanation":null,"reference":null,"responses":[{"text":"Mesonephros","correct":false,"visible":false},{"text":"Metanephros","correct":false,"visible":false},{"text":"Pronephros","correct":false,"visible":false},{"text":"Ureteric bud","correct":true,"visible":false},{"text":"Urogenital sinus","correct":false,"visible":false}]},{"id":7602,"text":"What is the most common congenital malformation of the urethra?","explanation":null,"reference":null,"responses":[{"text":"Meatal stenosis","correct":false,"visible":false},{"text":"Urethral stricture","correct":false,"visible":false},{"text":"Epispadias","correct":false,"visible":false},{"text":"Posterior urethral valve","correct":false,"visible":false},{"text":"Hypospadias","correct":true,"visible":false}]},{"id":7604,"text":"Ossification center of a fetus at the end of the ninth month or just before birth is seen in which of the following bones?","explanation":null,"reference":null,"responses":[{"text":"At the talus","correct":false,"visible":false},{"text":"The 2 ends of the clavicle","correct":false,"visible":false},{"text":"At the OS calcis","correct":false,"visible":false},{"text":"At the ribs and vertebra","correct":false,"visible":false},{"text":"The lower end of femur","correct":true,"visible":false}]},{"id":7606,"text":"A 55-year-old male comes with complaints of abdominal pain, high-grade fever with altered mental state, dysuria, and hematuria. His urine analysis report shows numerous pus cells, nitrite positive, and few red blood cells. He is diagnosed with a urinary tract infection. What would be the most common causative agent?","explanation":null,"reference":null,"responses":[{"text":"Haemophilus influenzae","correct":false,"visible":false},{"text":"Moraxella species","correct":false,"visible":false},{"text":"Vibrio cholerae","correct":false,"visible":false},{"text":"Escherichia coli","correct":true,"visible":false},{"text":"Shigella species","correct":false,"visible":false}]},{"id":7607,"text":"A 65-year-old man presents with hematuria, microcytic, hypochromic anemia, and right-sided hydronephrosis. CT scan reveals a mass in the right renal pelvis. The most likely diagnosis, in this case, would be.","explanation":null,"reference":null,"responses":[{"text":"Collecting duct carcinoma","correct":false,"visible":false},{"text":"Transitional cell carcinoma","correct":true,"visible":false},{"text":"Angiomyolipoma","correct":false,"visible":false},{"text":"Clear cell carcinoma","correct":false,"visible":false},{"text":"Oncocytoma","correct":false,"visible":false}]},{"id":7608,"text":"A 56-year-old patient who is a known case of diabetes mellitus type 2 presented with recurrent episodes, of burning micturition and pain lower abdomen. Which of the following investigation is pertinent at this stage?","explanation":null,"reference":null,"responses":[{"text":"Complete blood count","correct":false,"visible":false},{"text":"Serum creatinine","correct":false,"visible":false},{"text":"Blood culture and sensitivity","correct":false,"visible":false},{"text":"Urinalysis and culture and sensitivity","correct":true,"visible":false},{"text":"Blood sugar","correct":false,"visible":false}]},{"id":7609,"text":"A 50-year-old farmer has 8 children and his youngest son has been sick for the last 3 years and needs surgical intervention for complete recovery. He is already under debt of Rs. 100,000. He decides to sell his kidney to support his son and family. Considering the Islamic perspective on organ transplant, should he be allowed to sell a kidney for transplantation?","explanation":null,"reference":"Ilyas M, Alam M, Ahmad H. The islamic perspective of organ donation in Pakistan. Saudi Journal of Kidney Diseases and Transplantation. 2009:154. Accessed October 25, 2022. https://www.sjkdt.org/text.asp?2009/20/1/154/44727","responses":[{"text":"Islam prohibits the selling of an organ","correct":true,"visible":false},{"text":"Islam only allowed to use after permission from scholars","correct":false,"visible":false},{"text":"No such rule in Islam","correct":false,"visible":false},{"text":"Debates undergoing in Islam","correct":false,"visible":false},{"text":"Islam allows the sale of organs","correct":false,"visible":false}]},{"id":7610,"text":"A 30-year-old unmarried woman came to a doctor and requested her to induce an abortion. The doctor refused and told the women there is severe punishment for criminal abortion in Pakistan. What is the punishment of criminal abortion before babies' organs are formed in Pakistan?","explanation":null,"reference":"Pakistan’s abortion provisions. Center for Reproductive Rights. Accessed November 3, 2022. https://reproductiverights.org/maps/provision/pakistans-abortion-provisions/","responses":[{"text":"3 years imprisonment if with consent","correct":true,"visible":false},{"text":"7 years imprisonment","correct":false,"visible":false},{"text":"Full diyat of the child","correct":false,"visible":false},{"text":"1/20 diyat of the child","correct":false,"visible":false},{"text":"3 years imprisonment if without consent","correct":false,"visible":false}]},{"id":7633,"text":"Which of the following is true regarding bridegroom impotency?","explanation":null,"reference":null,"responses":[{"text":"It is temporary in nature","correct":true,"visible":false},{"text":"Seen in men who marry late","correct":false,"visible":false},{"text":"Commonly seen in diabetics","correct":false,"visible":false},{"text":"Seen in alcoholics","correct":false,"visible":false},{"text":"Due to fear of vaginismus","correct":false,"visible":false}]},{"id":7634,"text":"A 27-year-old woman presents with complaints of an increased urinary frequency with dysuria for the past 4 days. A urinalysis reveals sp. gr. 1.014, pH 7.5, no glucose, no protein, no blood, nitrite positive, and many WBC's. She has a serum creatinine of 0.9 mg/dL. Which of the following is the most likely diagnosis?","explanation":null,"reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 387.","responses":[{"text":"Lupus nephritis","correct":false,"visible":false},{"text":"Malakoplakia","correct":false,"visible":false},{"text":"Urinary lithiasis","correct":false,"visible":false},{"text":"Cystitis","correct":true,"visible":false},{"text":"Urothelial carcinoma","correct":false,"visible":false}]},{"id":7635,"text":"Which of the following is not an indication for dialysis in acute renal failure?","explanation":null,"reference":null,"responses":[{"text":"Pulmonary edema","correct":false,"visible":false},{"text":"Hyperkalemia","correct":false,"visible":false},{"text":"Metabolic acidosis","correct":false,"visible":false},{"text":"Uremic encephalopathy","correct":false,"visible":false},{"text":"\u003e2.5mg/dl serum creatinine","correct":true,"visible":false}]},{"id":7636,"text":"A fetus wrapped in an old newspaper was found in the garbage, brought by police to the medico-legal section for age determination. Haase's rule states what?","explanation":null,"reference":"Phillips B, Ong BB. “Was the infant born alive? ” a review of postmortem techniques used to determine live birth in cases of suspected neonaticide. Academic Forensic Pathology. 2018;8(4):874-893. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6491538/","responses":[{"text":"Crown heel length of the fetus in inches gives age in months in 1st five months","correct":false,"visible":false},{"text":"Square root of crown rump length in cm gives age of fetus in 1st five months","correct":false,"visible":false},{"text":"Crown Rump length of the fetus in cms gives age in months in 1st five month","correct":false,"visible":false},{"text":"Crown rump length of fetus in inches gives age in months in 1st five months","correct":false,"visible":false},{"text":"Square root of crown-heel length in cm gives age of fetus in 1st five months","correct":true,"visible":false}]},{"id":7637,"text":"A 45-year-old patient is admitted to the hospital due to a fracture of the tibia in a roadside accident. During operation a catheter was passed, such patients are prone to urinary tract infections. Which is the commonest causative agent in such a case?","explanation":null,"reference":null,"responses":[{"text":"Pseudomonas aeruginosa","correct":false,"visible":false},{"text":"Klebsiella species","correct":false,"visible":false},{"text":"E. coli","correct":true,"visible":false},{"text":"S. saprophyticus","correct":false,"visible":false},{"text":"Proteus species","correct":false,"visible":false}]},{"id":7638,"text":"The most appropriate measure to overcome diminished responsiveness to furosemide after its long-term use is what?","explanation":null,"reference":null,"responses":[{"text":"Potassium supplementation","correct":false,"visible":false},{"text":"Addition of a thiazide diuretic","correct":true,"visible":false},{"text":"Potassium restriction","correct":false,"visible":false},{"text":"Addition of acetazolamide","correct":false,"visible":false},{"text":"Switching over to parenteral administration of furosemide","correct":false,"visible":false}]},{"id":7639,"text":"What is the renal site where most water is reabsorbed?","explanation":null,"reference":null,"responses":[{"text":"Distal tubule","correct":false,"visible":false},{"text":"Medullary collecting tubule","correct":false,"visible":false},{"text":"Collecting duct","correct":false,"visible":false},{"text":"Loop of Henle","correct":false,"visible":false},{"text":"Early portions of the proximal tubule","correct":true,"visible":false}]},{"id":7640,"text":"A 23-year-old patient with flank pain and proteinuria was diagnosed with IgA nephropathy. Damage to the epithelium of the glomerulus may result in nephrotic syndrome. The epithelium is made up of different components. The visceral epithelium is formed by which of the following?","explanation":null,"reference":null,"responses":[{"text":"Podocytes","correct":true,"visible":false},{"text":"Transitional cells","correct":false,"visible":false},{"text":"Connective tissue","correct":false,"visible":false},{"text":"Fibroblasts","correct":false,"visible":false},{"text":"Endothelial cells","correct":false,"visible":false}]},{"id":7641,"text":"In a 24-year-old man suffering from a head injury in a motorcycle accident, what is the most appropriate agent to employ for the reduction of intracranial pressure?","explanation":null,"reference":null,"responses":[{"text":"Thiazide diuretic","correct":false,"visible":false},{"text":"Loop diuretic","correct":false,"visible":false},{"text":"Spirinolactone","correct":false,"visible":false},{"text":"Carbonic anhydrase inhibitor","correct":false,"visible":false},{"text":"Osmotic diuretic","correct":true,"visible":false}]},{"id":7642,"text":"A child of 5 years was brought to ED, with multiple bruises of different ages the child is a case of which of the following?","explanation":null,"reference":"Battered child syndrome - an overview | sciencedirect topics. Accessed October 24, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/battered-child-syndrome","responses":[{"text":"Battered baby syndrome","correct":true,"visible":false},{"text":"Culpable homicide not amounting to murder","correct":false,"visible":false},{"text":"Accidental injuries","correct":false,"visible":false},{"text":"Sudden infant death syndrome","correct":false,"visible":false},{"text":"Act of omission by parents","correct":false,"visible":false}]},{"id":7740,"text":"Filicide is defined by which of the following?","explanation":null,"reference":"Resnick PJ. Filicide in the united states. Indian Journal of Psychiatry. Published December 2016. Accessed October 24, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5282617/","responses":[{"text":"Killing of a new born child by the parents","correct":true,"visible":false},{"text":"Synonymous with criminal abortion","correct":false,"visible":false},{"text":"Killing of an illegitimate child","correct":false,"visible":false},{"text":"Killing of viable fetus inside the uterus","correct":false,"visible":false},{"text":"Killing of a disabled new born child","correct":false,"visible":false}]},{"id":7741,"text":"A 4-year-old boy is diagnosed as a case of nephrotic syndrome, first attack, and is on the appropriate dose of prednisone for ten days. His urinary protein creatinine ratio is \u003c0.2. What is the most appropriate classification of this child?","explanation":null,"reference":null,"responses":[{"text":"Partial remission","correct":false,"visible":false},{"text":"Initial responder","correct":false,"visible":false},{"text":"Steroid resistant","correct":false,"visible":false},{"text":"Steroid dependent","correct":false,"visible":false},{"text":"Complete remission","correct":true,"visible":false}]},{"id":7753,"text":"In a patient with non- dialysis-dependent chronic kidney disease (CKD), which management is known to reduce vascular events?","explanation":null,"reference":null,"responses":[{"text":"Anti-hypertensive drugs","correct":true,"visible":false},{"text":"Potassium restriction","correct":false,"visible":false},{"text":"Lipid lowering drugs","correct":false,"visible":false},{"text":"Protein restriction","correct":false,"visible":false},{"text":"Phosphate restriction","correct":false,"visible":false}]},{"id":7754,"text":"A 30-year-old male presented, to the outpatient department with a high-grade fever and sore throat for the last 3 days. For one day he noticed blood in urine and facial puffiness. On examination, his blood pressure was 150/90mmHg with mild pedal and facial edema. What are the likely diagnoses?","explanation":null,"reference":"Kumar, Vinay, et al. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed., Elsevier, 2020: 921.","responses":[{"text":"Lupus nephritis","correct":false,"visible":false},{"text":"Nephrotic syndrome","correct":false,"visible":false},{"text":"Post-streptococcal glomerulonephritis","correct":false,"visible":false},{"text":"IgA nephropathy","correct":true,"visible":false},{"text":"Wegener's granulomatosis","correct":false,"visible":false}]},{"id":7756,"text":"A pathologist is examining a specimen that is lined by transitional epithelium and showing three distinct smooth muscle layers in muscularis extena. The specimen he is observing is of what?","explanation":null,"reference":null,"responses":[{"text":"Bronchiole","correct":false,"visible":false},{"text":"vas deferens","correct":false,"visible":false},{"text":"Ureter","correct":true,"visible":false},{"text":"Urinary bladder","correct":false,"visible":false},{"text":"Urethra","correct":false,"visible":false}]},{"id":7759,"text":"Two boys living in a hostel were caught involved in a homosexual relationship. According to the Pakistan Penal Code (PPC) both of them if proven guilty will be liable to punishment under section?","explanation":null,"reference":"Pakistan Penal Code(Act XLV of 1860). Accessed October 25, 2022. https://pakistani.org/pakistan/legislation/1860/actXLVof1860.html","responses":[{"text":"294","correct":false,"visible":false},{"text":"295","correct":false,"visible":false},{"text":"376","correct":false,"visible":false},{"text":"375","correct":false,"visible":false},{"text":"377","correct":true,"visible":false}]},{"id":7761,"text":"The presence of which of the following casts are highly suggestive of acute tubular nephritis?","explanation":null,"reference":null,"responses":[{"text":"Granular casts","correct":false,"visible":false},{"text":"White blood cell casts","correct":false,"visible":false},{"text":"Red blood cell casts","correct":false,"visible":false},{"text":"Tubular cell casts","correct":true,"visible":false},{"text":"Hyaline casts","correct":false,"visible":false}]},{"id":7762,"text":"Microalbuminuria is defined as when the albumin excretion is noted with what level in normal urine volume?","explanation":null,"reference":null,"responses":[{"text":"Above 20 mcg per day","correct":false,"visible":false},{"text":"Less than 3.5gm per day","correct":false,"visible":false},{"text":"More than 3.5gm per day","correct":false,"visible":false},{"text":"Between 30 to 300mg per day","correct":true,"visible":false},{"text":"Between 0.5 to 1gm per day","correct":false,"visible":false}]},{"id":7764,"text":"A 65-year-old man notices blood in his urine. On examination, there is pain and tenderness in his left flank. A peripheral smear and complete blood count show mild microcytic, hypochromic anemia. A CT scan shows an irregular renal mass measuring 4.2 cm in diameter occupying the upper half of the left kidney. Which of the following is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Renal papillary adenoma","correct":false,"visible":false},{"text":"Renal cell carcinoma","correct":true,"visible":false},{"text":"Nephrolithiasis","correct":false,"visible":false},{"text":"Angiomyolipoma","correct":false,"visible":false},{"text":"Wilms tumor","correct":false,"visible":false}]},{"id":7765,"text":"A 9-year-old boy presents with nausea, headaches, and dizziness. He has recently recovered from tonsillitis. On examination, there is facial edema and blood pressure of 170/110 mmHg. A 24-hour urine collection measures 400ml. Urinalysis shows hematuria. Which of the following would be the most appropriate glomerular pathology in this case?","explanation":null,"reference":null,"responses":[{"text":"Minimal change nephritic syndrome","correct":false,"visible":false},{"text":"Glomerulosclerosis","correct":false,"visible":false},{"text":"Crescentric glomerulonephritis","correct":false,"visible":false},{"text":"Membranous glomerulonephritis","correct":false,"visible":false},{"text":"Post-infectious glomerulonephritis","correct":true,"visible":false}]},{"id":7865,"text":"What is the commonest presentation of bladder cancer?","explanation":null,"reference":null,"responses":[{"text":"Pain in supra pubic region","correct":false,"visible":false},{"text":"Increase frequency of micturition","correct":false,"visible":false},{"text":"Painless hematuria","correct":true,"visible":false},{"text":"Pain in flanks","correct":false,"visible":false},{"text":"Urinary retention","correct":false,"visible":false}]},{"id":7869,"text":"A 62-year-old man presents with a history of smoky urine for the last one week. On examination, there are no positive findings. A urine examination shows pH 5.5, 2+ blood, no protein, and no glucose. Urine cytology reveals atypical cells. Cystoscopy is normal. He has a 60 pack-year history of cigarette smoking. Which of the following is the most likely possibility in this case?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 964.","responses":[{"text":"Adenocarcinoma of prostate","correct":false,"visible":false},{"text":"Squamous cell carcinoma of penis","correct":false,"visible":false},{"text":"Acute interstitial nephritis","correct":false,"visible":false},{"text":"Nodular glomerulosclerosis","correct":false,"visible":false},{"text":"Urothelial carcinoma of renal pelvis","correct":true,"visible":false}]},{"id":7877,"text":"Orthostatic proteinuria is seen in which of the following conditions?","explanation":null,"reference":null,"responses":[{"text":"After overnight sleep","correct":false,"visible":false},{"text":"After high protein D","correct":false,"visible":false},{"text":"After prolonged standing","correct":true,"visible":false},{"text":"After seizures actively","correct":false,"visible":false},{"text":"After febrile illness","correct":false,"visible":false}]},{"id":7879,"text":"When is a miscarriage considered isqat-i-janin?","explanation":null,"reference":null,"responses":[{"text":"When no organs are formed","correct":false,"visible":false},{"text":"During the 1st trimester","correct":false,"visible":false},{"text":"When only limbs been formed","correct":false,"visible":false},{"text":"When some organs or limbs have been formed","correct":true,"visible":false},{"text":"During the 3rd trimester","correct":false,"visible":false}]},{"id":7881,"text":"A 6-month-old boy presented in emergency for high-grade fever. His blood CP results showed a high WBC count and CRP (C-reactive protein). Blood culture and urine culture confirmed the presence of E. coli. The physician came to the conclusion that the baby is suffering from a urinary tract infection that might be due to a congenital anomaly. Which one of the following is true related to congenital defects?","explanation":null,"reference":"Banker, Hiral, and Narothama R. Aeddula. “Vesicoureteral Reflux.” StatPearls, StatPearls Publishing, 2023. PubMed, http://www.ncbi.nlm.nih.gov/books/NBK563262/.","responses":[{"text":"Horse shoe kidney","correct":false,"visible":false},{"text":"Multicystic dysplastic kidney","correct":false,"visible":false},{"text":"Crossed fused renal ectopia","correct":false,"visible":false},{"text":"Renal dysplasia","correct":false,"visible":false},{"text":"Vesico-ureteral reflux","correct":true,"visible":false}]},{"id":7883,"text":"A 50-year-male present with generalized weakness his investigations show creatinine of 3mg/dl ultrasound abdomen shows bilateral small kidneys. What is the most common physical finding in chronic renal failure?","explanation":null,"reference":null,"responses":[{"text":"Hypertension","correct":false,"visible":false},{"text":"Anemia","correct":true,"visible":false},{"text":"Myopathy","correct":false,"visible":false},{"text":"Neuropathy","correct":false,"visible":false},{"text":"Pericarditis","correct":false,"visible":false}]},{"id":7894,"text":"Which of the following feature is most helpful in differentiating acute pyelonephritis from lower urinary tract infection?","explanation":null,"reference":null,"responses":[{"text":"Lipiduria","correct":false,"visible":false},{"text":"Proteinuria","correct":false,"visible":false},{"text":"White cell casts in urine","correct":true,"visible":false},{"text":"Hypertension","correct":false,"visible":false},{"text":"Glomerular immune-complex deposition","correct":false,"visible":false}]},{"id":7902,"text":"A 55-year-old man presents with generalized edema and ascites. Laboratory tests show: a total serum protein of 5.2g/dl (range: 5.5-8.0g/dl), albumin of 1.9g/dl (range: 3.5-5.5g/dl), and serum cholesterol of 540mg/dl. 24-hour urine collection reveals 4.8gms of protein loss. Urine contains many hyaline casts but no RBCs or WBCs. Immuno-fluorescence on renal biopsy shows granular sub-epithelial deposits along the glomerular basement membranes. Which one of the following would be the most appropriate glomerular pathology involved?","explanation":null,"reference":"Kumar, Vinay, et al. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed., Elsevier, 2020: 912, 913.","responses":[{"text":"Minimal change disease","correct":false,"visible":false},{"text":"Goodpasteurs syndrome","correct":false,"visible":false},{"text":"Membranous nephropathy","correct":true,"visible":false},{"text":"Membranoproliferative glomerulonephritis","correct":false,"visible":false},{"text":"Focal segmental glomerulosclerosis","correct":false,"visible":false}]},{"id":7908,"text":"Which of the following condition cannot cause normal anion gap metabolic acidosis?","explanation":null,"reference":null,"responses":[{"text":"Proximal renal tubular acidosis","correct":false,"visible":false},{"text":"Diabetic ketoacidosis","correct":true,"visible":false},{"text":"Urinary diversion procedure","correct":false,"visible":false},{"text":"Severe diarrhea","correct":false,"visible":false},{"text":"Bowel fistula (large size)","correct":false,"visible":false}]},{"id":7911,"text":"Surgical resection of an 8 cm well-circumscribed mass from an infant's abdomen reveals a predominantly solid and pale gray tumor with areas of cystic change, necrosis, and hemorrhage. Microscopically, it is composed of blastemal, stromal, and epithelial tissues. Which of the following is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Teratoma","correct":false,"visible":false},{"text":"Oncocytoma","correct":false,"visible":false},{"text":"Neuroblastoma","correct":false,"visible":false},{"text":"Renal cell carcinoma","correct":false,"visible":false},{"text":"Wilms tumor","correct":true,"visible":false}]},{"id":8036,"text":"What is a sperm count that is less than the reference value known as?","explanation":null,"reference":null,"responses":[{"text":"Aspermia","correct":false,"visible":false},{"text":"Teratozoospermia","correct":false,"visible":false},{"text":"Azoospermia","correct":false,"visible":false},{"text":"Oligozoospermia","correct":true,"visible":false},{"text":"Asthenospermia","correct":false,"visible":false},{"text":"Normozoospermia","correct":false,"visible":false}]},{"id":8037,"text":"Before a transplant, the renal transplant team visits the patient to take consent about the procedure and also from the family after counseling. For valid consent, the patient should be which of the following?","explanation":null,"reference":null,"responses":[{"text":"Competent","correct":false,"visible":false},{"text":"Autonomous","correct":false,"visible":false},{"text":"Confident","correct":false,"visible":false},{"text":"Social","correct":false,"visible":false},{"text":"Mature","correct":true,"visible":false}]},{"id":8038,"text":"A 7-year-old girl presents with puffiness around her eyes. Examination shows a blood pressure of 100/60 mmHg. Laboratory investigations show serum creatinine and urea nitrogen are within normal ranges. Urinalysis shows 4+ proteinuria, no blood, glucose, or ketones. The 24-hour urine protein content of 3.9g. The child's condition improves after a course of corticosteroid therapy. Which of the following is the best option to describe her condition?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 127-128.","responses":[{"text":"Nephrotic syndrome caused by cresentric glomerulonephritis","correct":false,"visible":false},{"text":"Nephritic syndrome due to post-infectious glomerulonephritis","correct":false,"visible":false},{"text":"Nephrotic syndrome due to membranoproliferative glomerulonephritis","correct":false,"visible":false},{"text":"Nephrotic syndrome due to minimal change disease","correct":true,"visible":false},{"text":"Chronic renal failure due to dense deposit disease","correct":false,"visible":false}]},{"id":8039,"text":"SIADH is characterized by which of the following?","explanation":null,"reference":null,"responses":[{"text":"Hypertonic hyponatremia","correct":false,"visible":false},{"text":"Euvolemic hypernatremia","correct":false,"visible":false},{"text":"Hypertonic hypernatremia","correct":false,"visible":false},{"text":"Hypotonic hyponatremia","correct":false,"visible":false},{"text":"Euvolumic hyponatremia","correct":true,"visible":false}]},{"id":8040,"text":"A 20-year-old man is brought into the emergency room after a morphine overdose.  Upon examination, he is unconscious, pupils are pinpoint and non-reactive. Several injection marks are seen on his arms. What is the immediate treatment after maintaining the airway, breathing, and circulation?","explanation":null,"reference":"Biswas, Gautam. Review of Forensic Medicine and Toxicology. 3rd ed., Jaypee Brothers Medical Publishers, 2015: 539.","responses":[{"text":"Gastric lavage","correct":false,"visible":false},{"text":"Gastric lavage with tannic acid","correct":false,"visible":false},{"text":"Naloxone with gastric lavage","correct":false,"visible":false},{"text":"Naloxone","correct":true,"visible":false},{"text":"Naloxone with pethidine","correct":false,"visible":false}]},{"id":8041,"text":"In Pakistan, on which grounds is abortion justifiable?","explanation":null,"reference":"“Pakistan’s Abortion Provisions.” Center for Reproductive Rights, https://reproductiverights.org/maps/provision/pakistans-abortion-provisions/. Accessed 17 Nov. 2023.","responses":[{"text":"Social grounds","correct":false,"visible":false},{"text":"Eugenic grounds","correct":false,"visible":false},{"text":"Therapeutic grounds","correct":true,"visible":false},{"text":"Threatened","correct":false,"visible":false},{"text":"Humanitarian grounds","correct":false,"visible":false}]},{"id":8042,"text":"A 58-year-old male presents with pain and tenderness at the right costovertebral angle. Laboratory investigations reveal microscopic haematuria but no protein or glucose. A complete blood count report shows microcytic hypochromic anemia. CT scan reveals an irregular renal mass 6 cm in diameter near the upper pole of the right kidney. Biopsy reveals atypical cells with abundant clear cytoplasm. Molecular studies would most likely identify mutations in which of the following growth regulatory genes?","explanation":null,"reference":null,"responses":[{"text":"VHL","correct":true,"visible":false},{"text":"IGF-2","correct":false,"visible":false},{"text":"WT1","correct":false,"visible":false},{"text":"Rb","correct":false,"visible":false},{"text":"p53","correct":false,"visible":false}]},{"id":8043,"text":"A middle-aged man experiences increasing malaise, nausea with reduced urine output for the past two days. Laboratory investigations show a raised serum creatinine of 2.7mg/dl. Urinalysis shows hematuria. Renal biopsy reveals granular pattern on immunofluorescence. Which of the following best describes this patient's medical condition?","explanation":null,"reference":null,"responses":[{"text":"HIV nephropathy","correct":false,"visible":false},{"text":"Membranous glomerulonephritis","correct":false,"visible":false},{"text":"Focal segmental glomerulosclerosis","correct":false,"visible":false},{"text":"Crescentic glomerulonephritis","correct":true,"visible":false},{"text":"Lupus nephritis","correct":false,"visible":false}]},{"id":8044,"text":"A 22-year-old female presented with abrupt onset of hematuria, hypertension, and peripheral edema. Initial investigations show transient renal dysfunction with protein and red blood cell casts in urine. What is the likely diagnosis as per presentation in this case?","explanation":null,"reference":null,"responses":[{"text":"Acute nephritic syndrome","correct":true,"visible":false},{"text":"Acute tubular necrosis","correct":false,"visible":false},{"text":"Nephritic syndrome","correct":false,"visible":false},{"text":"Acute urinary tract infection","correct":false,"visible":false},{"text":"Asymptomatic proteinuria with hematuria","correct":false,"visible":false}]},{"id":8045,"text":"A 70-year-old male presents with complaints of pain in the groin, hematuria, and anuria. Ultrasound shows complete bilateral obstruction with dilated pelvis and calyces. The physician diagnoses him with hydronephrosis. What is the site of obstruction?","explanation":null,"reference":null,"responses":[{"text":"At the pelvis","correct":false,"visible":false},{"text":"Below ureter","correct":true,"visible":false},{"text":"In renal medulla","correct":false,"visible":false},{"text":"Above ureter","correct":false,"visible":false},{"text":"In collecting tubules","correct":false,"visible":false}]},{"id":8049,"text":"Which of the following conditions does not favor the development of \"maceration\" in a dead fetus inside the uterine cavity?","explanation":null,"reference":"Subrahmanyam BV. Parikh’s Textbook of Medical Jurisprudence, Forensic Medicine and Toxicology for Classrooms and Courtrooms. 8th ed. CBS Publishers; 2019: 444.","responses":[{"text":"Dead fetus remains inside uterus for at least 24 hours","correct":false,"visible":false},{"text":"Fetus dies in uterus","correct":false,"visible":false},{"text":"Membranes ruptured","correct":true,"visible":false},{"text":"Dead fetus is surrounded by liqor amni","correct":false,"visible":false},{"text":"Membranes intact","correct":false,"visible":false}]},{"id":8063,"text":"A 25-year-old man presents with the symptoms of nephrotic syndrome. A biopsy of the kidneys, on electron microscopy, shows effacement of podocyte foot processes. What is the diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Minimal change disease","correct":true,"visible":false},{"text":"Rapidly progressive glomerulonephritis","correct":false,"visible":false},{"text":"Acute pyelonephritis","correct":false,"visible":false},{"text":"Chronic pyelonephritis","correct":false,"visible":false},{"text":"IgA nephropathy","correct":false,"visible":false}]},{"id":8069,"text":"What is the most common complication of a child with nephrotic syndrome?","explanation":null,"reference":null,"responses":[{"text":"Renal vein thrombosis","correct":false,"visible":false},{"text":"Protein malnutrition","correct":false,"visible":false},{"text":"Vitamin D deficiency","correct":false,"visible":false},{"text":"Infections","correct":true,"visible":false},{"text":"Deep vein thrombosis","correct":false,"visible":false}]},{"id":8080,"text":"Hospital waste can be classified into various types. Among the following which one is classified as pathological waste?","explanation":null,"reference":"Health-care waste. Accessed October 20, 2022. https://www.who.int/news-room/fact-sheets/detail/health-care-waste","responses":[{"text":"Waste from infected patients","correct":false,"visible":false},{"text":"Waste from surgery","correct":false,"visible":false},{"text":"Waste from infected animals","correct":false,"visible":false},{"text":"Cultures from laboratory work","correct":false,"visible":false},{"text":"Organs","correct":true,"visible":false}]},{"id":8082,"text":"A 25-year-old woman with acute pyelonephritis was treated with oral ciprofloxacin. On day 8 of antibiotic treatment, the patient developed a maculopapular rash, low-grade fever, and eosinophilia. Serum creatinine was 2 mg/dl (baseline: 0.7 mg/dl). What would be the diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Chronic granulomatous prostatitis","correct":false,"visible":false},{"text":"Drug induced interstitial nephritis","correct":true,"visible":false},{"text":"Benign prostate hypertrophy","correct":false,"visible":false},{"text":"Chronic reflux-associated pyelonephritis","correct":false,"visible":false},{"text":"Chronic obstructive pyelonephritis","correct":false,"visible":false}]},{"id":8085,"text":"During the first three months, what is the best-skilled method of termination of pregnancy?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 35.","responses":[{"text":"Prostaglandins","correct":false,"visible":false},{"text":"Abortion stick","correct":false,"visible":false},{"text":"Electricity","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Vaccum aspiration","correct":true,"visible":false}]},{"id":8086,"text":"30-year-old Arshad is dependent on morphine as it makes him feel good and also reports that it makes him feel light and relaxed. What are the properties of opium and its derivatives for which they are potentially used as drugs of abuse?","explanation":null,"reference":"Narcotic analgesic agent - an overview | sciencedirect topics. Accessed October 24, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/narcotic-analgesic-agent","responses":[{"text":"Analgesia and narcosis","correct":true,"visible":false},{"text":"Analgesia and sedation","correct":false,"visible":false},{"text":"Analgesia","correct":false,"visible":false},{"text":"Narcosis","correct":false,"visible":false},{"text":"Sedative","correct":false,"visible":false}]},{"id":8088,"text":"The use of potassium-sparing diuretics in patients receiving which of the following drugs needs close monitoring?","explanation":null,"reference":null,"responses":[{"text":"Furosemide","correct":false,"visible":false},{"text":"Verapamil","correct":false,"visible":false},{"text":"Nifedipine","correct":false,"visible":false},{"text":"Captopril","correct":true,"visible":false},{"text":"Hydrochlorothiazide","correct":false,"visible":false}]},{"id":8090,"text":"What is the treatment for hypernatremia in patients with chronic liver disease with ascites?","explanation":null,"reference":null,"responses":[{"text":"Diuretics","correct":true,"visible":false},{"text":"Water restriction","correct":false,"visible":false},{"text":"Water restriction with diuretics","correct":false,"visible":false},{"text":"Normal saline","correct":false,"visible":false},{"text":"Hypertonic saline","correct":false,"visible":false}]},{"id":8093,"text":"Which one of the following types of kidney stone formation is associated with a bacterial infection?","explanation":null,"reference":null,"responses":[{"text":"Calcium phosphate stone","correct":false,"visible":false},{"text":"Calcium oxalate stone","correct":false,"visible":false},{"text":"Calcium maleate stone","correct":false,"visible":false},{"text":"Magnesium ammonium phosphate","correct":true,"visible":false},{"text":"Uric acid stones","correct":false,"visible":false}]},{"id":8094,"text":"A 22-year-old woman presents with swelling of the legs. On urinalysis, there was increased proteinuria. She is diagnosed to have tubulointerstitial nephritis. It could have been drug-induced. It is characterized by which of the following?","explanation":null,"reference":null,"responses":[{"text":"Increased glomerular filtration rate and oliguria","correct":false,"visible":false},{"text":"Dose dependent severity of the disease","correct":false,"visible":false},{"text":"Appearance of symptoms after about two weeks of exposure","correct":true,"visible":false},{"text":"Decreased blood urea nitrogen","correct":false,"visible":false},{"text":"Increased urinary sugar level","correct":false,"visible":false}]},{"id":8097,"text":"Which of the following is the hallmark of nephritic syndrome?","explanation":null,"reference":null,"responses":[{"text":"Hematuria","correct":true,"visible":false},{"text":"Hyponatremia","correct":false,"visible":false},{"text":"Hypertension with salt and water retreatment","correct":false,"visible":false},{"text":"Edema","correct":false,"visible":false},{"text":"Loin pain","correct":false,"visible":false}]},{"id":8098,"text":"A 50-year-old man has noted passing darker urine for the past week. On physical examination, there are no abnormal findings. A urinalysis shows pH 5.5, specific gravity 1.013, 2+ blood, no protein, and no glucose. Urine cytology is performed and there are atypical uroepithelial cells seen. A urologist performs a cystoscopy, but no mucosal lesions are noted. He has a 60 pack-year history of smoking cigarettes. Which of the following is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Urothelial carcinoma of renal pelvis","correct":true,"visible":false},{"text":"Nodular glomerulosclerosis","correct":false,"visible":false},{"text":"Squamous cell carcinoma of penis","correct":false,"visible":false},{"text":"Acute interstitial nephritis","correct":false,"visible":false},{"text":"Adenocarcinoma of prostate","correct":false,"visible":false}]},{"id":8099,"text":"Whosoever causes a woman with child, whose organs have been formed to miscarry, without good faith for the purpose of saving the life of the woman is known as what?","explanation":null,"reference":"338B. Pakistan Penal Code (Act XLV of 1860). Accessed October 25, 2022. https://pakistani.org/pakistan/legislation/1860/actXLVof1860.html","responses":[{"text":"Shajjah-i-hashimiah","correct":false,"visible":false},{"text":"Shajjah-i-damighah","correct":false,"visible":false},{"text":"Isqat-e-janin","correct":true,"visible":false},{"text":"Isqat-e-haml","correct":false,"visible":false},{"text":"Shajjah-i-ammah","correct":false,"visible":false}]},{"id":8100,"text":"A graduate student is planning to make a high-altitude climb in South America while on vacation. He will not have time to acclimate slowly to the altitude. What drug is useful in preventing high-altitude sickness?","explanation":null,"reference":"Paralikar, Swapnil J., and Jagdish H. Paralikar. “High-Altitude Medicine.” Indian Journal of Occupational and Environmental Medicine, 2010, https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2923424/.","responses":[{"text":"Desmopressin","correct":false,"visible":false},{"text":"Acetazolamide","correct":true,"visible":false},{"text":"Demeclocycline","correct":false,"visible":false},{"text":"Amiloride","correct":false,"visible":false},{"text":"Ethacrynic acid","correct":false,"visible":false}]},{"id":8101,"text":"Pyelonephritis is encountered frequently in clinical settings. Gram-negative organisms are frequently implicated. What is the most common causative organism?","explanation":null,"reference":null,"responses":[{"text":"Pseudomonas","correct":false,"visible":false},{"text":"Escherichia coli","correct":true,"visible":false},{"text":"Enterobacter","correct":false,"visible":false},{"text":"Klebsiella","correct":false,"visible":false},{"text":"Proteus","correct":false,"visible":false}]},{"id":8106,"text":"A 30-year-old man has noted puffiness around his eyes and swelling of his feet for the past 2 weeks. On physical examination, his blood pressure is 155/95 mm Hg. Urine microscopic examination reveals oval fat bodies. Which of the following conditions is he most likely to have?","explanation":null,"reference":null,"responses":[{"text":"Obstructive uropathy","correct":false,"visible":false},{"text":"Renal infarction","correct":false,"visible":false},{"text":"Nephritic syndrome","correct":false,"visible":false},{"text":"Ascending pyelonephritis","correct":false,"visible":false},{"text":"Nephrotic syndrome","correct":true,"visible":false}]},{"id":8109,"text":"Polycystic kidney diseases are genetic diseases. Polycystin 1 gene, is implicated in which of the following?","explanation":null,"reference":null,"responses":[{"text":"Cysts associated with dialysis","correct":false,"visible":false},{"text":"Solitary cysts","correct":false,"visible":false},{"text":"Adult polycystic kidney disease","correct":true,"visible":false},{"text":"Childhood polycystic kidney disease","correct":false,"visible":false},{"text":"Medullary sponge kidney","correct":false,"visible":false}]},{"id":8110,"text":"What is the most important parameter for the analysis of arterial blood gases (ABGs)?","explanation":null,"reference":null,"responses":[{"text":"Anion gap","correct":false,"visible":false},{"text":"pH","correct":false,"visible":false},{"text":"pCO2","correct":false,"visible":false},{"text":"pH, PCO2, HCO3- values","correct":true,"visible":false},{"text":"Calculate the range of the compensatory response","correct":false,"visible":false}]},{"id":8344,"text":"A 40-year-old male patient has presented with decreased urinary output of 5 days duration after he has been bitten by a snake. Which of the following investigations should be performed initially in this patient with acute renal failure?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 411.","responses":[{"text":"CT scan abdomen","correct":false,"visible":false},{"text":"Serum parathyroid hormone","correct":false,"visible":false},{"text":"Urine detailed report (urine D/R)","correct":true,"visible":false},{"text":"Urine electrolytes","correct":false,"visible":false},{"text":"Urine microalbumin level","correct":false,"visible":false}]},{"id":8345,"text":"What is the least likely cause of a urinary tract infection?","explanation":null,"reference":null,"responses":[{"text":"Autonomic neuropathy","correct":true,"visible":false},{"text":"Renal stone","correct":false,"visible":false},{"text":"Benign prostatic hypertrophy","correct":false,"visible":false},{"text":"Foley's catheter","correct":false,"visible":false},{"text":"Diabetes mellitus","correct":false,"visible":false}]},{"id":8357,"text":"In acute nephritic syndrome, children and young adults are affected. Which is the most common age range for nephritic syndrome?","explanation":null,"reference":null,"responses":[{"text":"10-20 years","correct":false,"visible":false},{"text":"5-6 years","correct":false,"visible":false},{"text":"6-10 years","correct":true,"visible":false},{"text":"0-2 years","correct":false,"visible":false},{"text":"2-4 years","correct":false,"visible":false}]},{"id":8358,"text":"A 50-year-old man has a history of frequent episodes of renal colic with high calcium renal stones. Which of the following agents is most useful in the treatment of recurrent calcium stones?","explanation":null,"reference":null,"responses":[{"text":"Spirinolactone","correct":false,"visible":false},{"text":"Furosemide","correct":false,"visible":false},{"text":"Hydrochlorothiazide","correct":true,"visible":false},{"text":"Acetazolamide","correct":false,"visible":false},{"text":"Mannitol","correct":false,"visible":false}]},{"id":8360,"text":"A 60-year-old male, known case of diabetes mellitus, presents to the outpatient department, with complaints of uncontrolled blood sugar and bilateral pedal edema, gradually increasing for 4 months. On examination anemia and pitting edema is present. Laboratory results show hemoglobin: 10.1 gm/dl, total leukocyte count (TLC), and platelets: normal, urea: 60 mg/dl, serum creatinine: 2.0 mg/dl, eGFR \u003c 60 ml/min/1.73m2. The most appropriate first investigation will be:","explanation":null,"reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 743.","responses":[{"text":"Ultrasound abdomen","correct":false,"visible":false},{"text":"Urine D/R","correct":true,"visible":false},{"text":"Albumin to creatinine ratio","correct":false,"visible":false},{"text":"Serum albumin","correct":false,"visible":false},{"text":"Renal biopsy","correct":false,"visible":false}]},{"id":8362,"text":"What is the commonest presentation of Wilms tumor?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 483.","responses":[{"text":"Urinary retention","correct":false,"visible":false},{"text":"Abdominal mass","correct":true,"visible":false},{"text":"Hematuria","correct":false,"visible":false},{"text":"Fever","correct":false,"visible":false},{"text":"Abdominal pain","correct":false,"visible":false}]},{"id":8364,"text":"What is the most common presentation of a road traffic accident victim who has suffered from severe renal trauma?","explanation":null,"reference":null,"responses":[{"text":"Shock","correct":false,"visible":false},{"text":"Clot colic","correct":false,"visible":false},{"text":"Bruising in the loin","correct":false,"visible":false},{"text":"Hematuria","correct":true,"visible":false},{"text":"Abdominal distension","correct":false,"visible":false}]},{"id":8365,"text":"The mother of a 9-month-old boy notices a mass on the right side of the infant's abdomen. Resection of the mass reveals a 10 cm well-circumscribed tumor which is of soft consistency. The cut section of the tumor is predominantly solid and pale gray with areas of cystic change, necrosis, and hemorrhage. Microscopically, the tumor is composed of blastemal, stromal, and epithelial tissues. Which of the following is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Angiomyolipoma","correct":false,"visible":false},{"text":"Neuroblastoma","correct":false,"visible":false},{"text":"Wilms tumor","correct":true,"visible":false},{"text":"Renal cell carcinoma","correct":false,"visible":false},{"text":"Oncocytoma","correct":false,"visible":false}]},{"id":8368,"text":"Benign prostatic hyperplasia (BPH) is an extremely common cause of prostatic enlargement resulting from the proliferation of stromal and glandular elements. The enlargement of the prostate in men with BPH is an important cause of urinary obstruction. Which zone is commonly involved in benign prostatic hyperplasia?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 437.","responses":[{"text":"Posterior","correct":false,"visible":false},{"text":"Fibromuscular","correct":false,"visible":false},{"text":"Central","correct":false,"visible":false},{"text":"Transitional","correct":true,"visible":false},{"text":"Anterior","correct":false,"visible":false}]},{"id":8369,"text":"A 20-year-old-man comes with flank pain and urinary symptoms. He is diagnosed with having polycystic kidney disease. His family has a known mutation in the PKHD1 gene. PKHD1 gene, coding for a membrane receptor protein called fibrocystin is implicated in which of the following?","explanation":null,"reference":null,"responses":[{"text":"Cysts associated with dialysis","correct":false,"visible":false},{"text":"Adult polycystic kidney disease","correct":false,"visible":false},{"text":"Childhood polycystic kidney disease","correct":true,"visible":false},{"text":"Solitary cysts","correct":false,"visible":false},{"text":"Medullary sponge kidney","correct":false,"visible":false}]},{"id":8370,"text":"A 24-year-old patient presents with edema and hypertension is diagnosed with nephrotic syndrome. It can develop as a result of a number of renal injuries. What is it characterized by?","explanation":null,"reference":null,"responses":[{"text":"Hypolipidemia and lipiduria","correct":false,"visible":false},{"text":"Proteinuria and hypoalbuminemia","correct":true,"visible":false},{"text":"Decreased urinary creatinine","correct":false,"visible":false},{"text":"Increased urinary sugar level","correct":false,"visible":false},{"text":"Proteinuria and hyperalbuminemia","correct":false,"visible":false}]},{"id":8371,"text":"One of the signs of remote delivery in the living women is the presence of linea nigra a dark line of pigmentation in what location?","explanation":null,"reference":"Vora, Rita V., et al. “Pregnancy and Skin.” Journal of Family Medicine and Primary Care, vol. 3, no. 4, 2014, pp. 318–24. PubMed Central, https://doi.org/10.4103/2249-4863.148099.","responses":[{"text":"From umbilicus to ensiform cartilage","correct":false,"visible":false},{"text":"From pubis to umbilicus","correct":false,"visible":false},{"text":"Upper part of thigh","correct":false,"visible":false},{"text":"From pubis to ensiform cartilage","correct":true,"visible":false},{"text":"Around umbilicus","correct":false,"visible":false}]},{"id":8372,"text":"A post mortem examination was conducted on a 38-year-old parous woman to see the signs of remote delivery, what are the findings that would confirm the diagnosis?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 362.","responses":[{"text":"The external os is vertical irregular and admit 2 fingers","correct":false,"visible":false},{"text":"The cervix and body of uterus are about the same length","correct":false,"visible":false},{"text":"The internal os is soft, patulous, rounded with a dimple in the center","correct":false,"visible":false},{"text":"The top of fundus is at a lower level than that of broad ligament","correct":false,"visible":false},{"text":"The walls of a uterus are concave from inside forming a wider and rounded cavity","correct":true,"visible":false}]},{"id":8374,"text":"The hydrostatic pressure in Bowman's capsule is 18 mmHg, the hydrostatic pressure in glomerular capillaries is 60 mmHg, and colloidal osmotic pressure in the glomerular capillaries is 32 mmHg. What should be the net pressure to drive glomerular filtration?","explanation":null,"reference":null,"responses":[{"text":"46 mmHg","correct":false,"visible":false},{"text":"10 mmHg","correct":true,"visible":false},{"text":"28 mmHg","correct":false,"visible":false},{"text":"74 mmHg","correct":false,"visible":false},{"text":"110 mmHg","correct":false,"visible":false}]},{"id":8375,"text":"A 33-year-old patient presents with bilateral swelling of the legs. On a detailed urine report, she was found to have increased proteinuria. She was diagnosed to have acute kidney injury. What features would suggest immune involvement in acute kidney injury?","explanation":null,"reference":null,"responses":[{"text":"Dose dependent reaction","correct":false,"visible":false},{"text":"Absence of cross reactivity","correct":false,"visible":false},{"text":"Reaction occurring without drug exposure","correct":false,"visible":false},{"text":"Eosinophilia and rash","correct":true,"visible":false},{"text":"No recurrence of the reaction","correct":false,"visible":false}]},{"id":8376,"text":"Patients with nephrotic syndrome are vulnerable to infections due to loss of immunoglobulins in urine or nonselective proteinuria. Which of the following is the most common organism causing infections in a nephrotic syndrome patient?","explanation":null,"reference":null,"responses":[{"text":"Mycoplasma pneumoniae","correct":false,"visible":false},{"text":"Streptococcus pneumoniae","correct":true,"visible":false},{"text":"Mycobacterium tuberculosis","correct":false,"visible":false},{"text":"Coxiella burnetti","correct":false,"visible":false},{"text":"E. coli","correct":false,"visible":false}]},{"id":8377,"text":"A 66-year-old woman complaining of dysuria, polyuria, intermittent gross hematuria, and chronic low back pain. She had a history of urinary tract infections and pyelonephritis of the kidney. Urinalysis revealed urine sedimentation, a pH of 9.0, leukocyte esterase positive, nitrite positive, WBC 90-100/HPF, RBC 60-80/HPF. A KUB radiograph showed large calcifications in both kidneys. What is the most likely composition of these calcifications?","explanation":null,"reference":null,"responses":[{"text":"Cystine stone","correct":false,"visible":false},{"text":"Calcium phosphate stone","correct":false,"visible":false},{"text":"Calcium oxalate stone","correct":false,"visible":false},{"text":"Uric acid stone","correct":false,"visible":false},{"text":"Struvite stone","correct":true,"visible":false}]},{"id":8378,"text":"A group of medical students wants to conduct research on the serum and urine parameters of patients with minimal change disease. Which of the following laboratory test findings is most likely to be consistently present in these subjects?","explanation":null,"reference":null,"responses":[{"text":"Hematuria","correct":false,"visible":false},{"text":"Proteinuria \u003e3.5 gm/24 hours","correct":true,"visible":false},{"text":"Lipiduria in association with hypercholesterolemia","correct":false,"visible":false},{"text":"Renal tubular epithelial cells and casts","correct":false,"visible":false},{"text":"Nitrite positive urinalysis specimen","correct":false,"visible":false}]},{"id":8379,"text":"A 30-year-old man is brought into the emergency room after he overdosed on an unknown drug. On examination, his pupils are constricted, nonreactive to light, his breathing is sighing and irregular in pattern, his body is profusely sweating. Based on these findings, what has he overdosed on?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 538.","responses":[{"text":"Naloxone","correct":false,"visible":false},{"text":"Naphthalene","correct":false,"visible":false},{"text":"Milk of magnesia","correct":false,"visible":false},{"text":"Morphine","correct":true,"visible":false},{"text":"Kerosene oil","correct":false,"visible":false}]},{"id":8380,"text":"A 12-year-old girl has a history of throat infection with group A (ß-hemolytic) streptococci. Now she presents with hypertension, oliguria, and hematuria. Renal biopsy shows glomerulonephritis. Immunofluorescence microscopy in this case is most likely to show which of the following protein deposition in the glomeruli?","explanation":null,"reference":null,"responses":[{"text":"Complement","correct":true,"visible":false},{"text":"Plasminogen","correct":false,"visible":false},{"text":"Fibrinogen","correct":false,"visible":false},{"text":"Thrombin","correct":false,"visible":false},{"text":"Albumin","correct":false,"visible":false}]},{"id":8381,"text":"A 43-year-old man complains of increased fatigue and malaise for 3 weeks. His blood pressure is 150/95 mmHg.  On examination, there is pitting edema of the lower limbs extending up to the knees. Urinalysis shows no glucose, blood, ketones, nitrite, or urobilinogen. Microscopic examination of urine exhibits no RBC or WBC. 24-hour urine protein is 4.2 gm. Serum creatinine and urea are high (3.5 mg/dL and 38 mg/dL respectively). Serum HBsAg is positive. Which of the following pathological condition is the possible diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Membranous nephropathy","correct":true,"visible":false},{"text":"Diabetic nephropathy","correct":false,"visible":false},{"text":"Acute tubular necrosis","correct":false,"visible":false},{"text":"Poststreptococcal glomerulonephritis","correct":false,"visible":false},{"text":"Systemic lupus erythematosus","correct":false,"visible":false}]},{"id":8382,"text":"Two infants in different stages of development may be born in which of the following conditions?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 359.","responses":[{"text":"Homologous artificial insemination","correct":false,"visible":false},{"text":"Ectopic pregnancy","correct":false,"visible":false},{"text":"Superfoetation","correct":true,"visible":false},{"text":"Heterozygotic twins","correct":false,"visible":false},{"text":"Superfecundation","correct":false,"visible":false}]},{"id":8383,"text":"What is the best treatment for localized T1 and T2 staged carcinoma prostate, in men less than 70 years?","explanation":null,"reference":null,"responses":[{"text":"Chemotherapy","correct":false,"visible":false},{"text":"Radical prostatectomy","correct":true,"visible":false},{"text":"Bilateral orchidectomy","correct":false,"visible":false},{"text":"Radiotherapy (external beam)","correct":false,"visible":false},{"text":"Strontium 89 radiotherapy","correct":false,"visible":false}]}
]

export default a